12		"github.com/go-git/go-git/v5/plumbing"
13		"github.com/soph/git-sync/internal/syncer"
14	)
15	
16	func main() {
17		if err := run(context.Background(), os.Args[1:]); err != nil {
18			fmt.Fprintf(os.Stderr, "error: %v\n", err)
19			os.Exit(1)
20		}
21	}
22	
23	func run(ctx context.Context, args []string) error {
24		if len(args) == 0 {
25			return usageError("")
26		}
27	
28		switch args[0] {
29		case "sync":
30			return runSyncLike(ctx, "sync", args[1:], false)
31		case "plan":
32			return runSyncLike(ctx, "plan", args[1:], true)
33		case "bootstrap":
34			return runBootstrap(ctx, args[1:])
35		case "probe":
36			return runProbe(ctx, args[1:])
37		case "fetch":
38			return runFetch(ctx, args[1:])
39		case "help", "-h", "--help":
40			return usageError("")
41		default:
42			return usageError(fmt.Sprintf("unknown command %q", args[0]))
43		}
44	}
45	
46	func runSyncLike(ctx context.Context, name string, args []string, dryRun bool) error {
47		fs := flag.NewFlagSet(name, flag.ContinueOnError)
48		fs.SetOutput(os.Stderr)
49	
50		cfg := syncer.Config{DryRun: dryRun}
51		var mappings multiStringFlag
52		var jsonOutput bool
53	
54		fs.StringVar(&cfg.Source.URL, "source-url", "", "source repository URL")
55		fs.StringVar(&cfg.Target.URL, "target-url", "", "target repository URL")
56	
57		fs.StringVar(&cfg.Source.Token, "source-token", envOr("GITSYNC_SOURCE_TOKEN", ""), "source token/password")
58		fs.StringVar(&cfg.Target.Token, "target-token", envOr("GITSYNC_TARGET_TOKEN", ""), "target token/password")
59		fs.StringVar(&cfg.Source.Username, "source-username", envOr("GITSYNC_SOURCE_USERNAME", "git"), "source basic auth username")
60		fs.StringVar(&cfg.Target.Username, "target-username", envOr("GITSYNC_TARGET_USERNAME", "git"), "target basic auth username")
61		fs.BoolVar(&cfg.Source.SkipTLSVerify, "source-insecure-skip-tls-verify", envBool("GITSYNC_SOURCE_INSECURE_SKIP_TLS_VERIFY"), "skip TLS certificate verification for the source")
62		fs.BoolVar(&cfg.Target.SkipTLSVerify, "target-insecure-skip-tls-verify", envBool("GITSYNC_TARGET_INSECURE_SKIP_TLS_VERIFY"), "skip TLS certificate verification for the target")
63	
64		fs.StringVar(&cfg.Source.BearerToken, "source-bearer-token", envOr("GITSYNC_SOURCE_BEARER_TOKEN", ""), "source bearer token")
65		fs.StringVar(&cfg.Target.BearerToken, "target-bearer-token", envOr("GITSYNC_TARGET_BEARER_TOKEN", ""), "target bearer token")
66	
67		branches := fs.String("branch", "", "comma-separated branch list; default is all source branches")
68		fs.Var(&mappings, "map", "ref mapping in src:dst form; short names map branches, full refs map exact refs")
69		fs.BoolVar(&cfg.IncludeTags, "tags", false, "mirror tags")
70		fs.BoolVar(&cfg.Force, "force", false, "allow non-fast-forward branch updates and retarget tags")
71		fs.BoolVar(&cfg.Prune, "prune", false, "delete managed target refs that no longer exist on source")
72		fs.BoolVar(&cfg.ShowStats, "stats", false, "print transfer statistics")
73		fs.BoolVar(&cfg.MeasureMemory, "measure-memory", false, "sample elapsed time and Go heap usage")
74		fs.BoolVar(&jsonOutput, "json", false, "print JSON output")
75		fs.StringVar(&cfg.ProtocolMode, "protocol", envOr("GITSYNC_PROTOCOL", "auto"), "protocol mode: auto, v1, or v2")
76		fs.BoolVar(&cfg.Verbose, "v", false, "verbose logging")
77	
78		if err := fs.Parse(args); err != nil {
79			return err
80		}
81	
82		positional := fs.Args()
83		if cfg.Source.URL == "" && len(positional) > 0 {
84			cfg.Source.URL = positional[0]
85		}
86		if cfg.Target.URL == "" && len(positional) > 1 {
87			cfg.Target.URL = positional[1]
88		}
89		if len(positional) > 2 {
90			return usageError("too many positional arguments")
91		}
92	
93		if *branches != "" {
94			cfg.Branches = splitCSV(*branches)
95		}
96		for _, raw := range mappings {
97			mapping, err := parseMapping(raw)
98			if err != nil {
99				return err
100			}
101			cfg.Mappings = append(cfg.Mappings, mapping)
102		}
103	
104		if cfg.Source.URL == "" || cfg.Target.URL == "" {
105			return usageError(name + " requires source and target repository URLs")
106		}
107	
108		result, err := syncer.Run(ctx, cfg)
109		if err != nil {
110			return err
111		}
112		printOutput(jsonOutput, result)
113	
114		if !dryRun && result.Blocked > 0 {
115			return errors.New("one or more branches were skipped because the target was not fast-forwardable")
116		}
117		return nil
118	}
