397	func Run(ctx context.Context, cfg Config) (Result, error) {
398		measurementDone := startMeasurement(cfg.MeasureMemory)
399		if cfg.ProtocolMode == "" {
400			cfg.ProtocolMode = protocolModeAuto
401		}
402		if cfg.ProtocolMode != protocolModeAuto && cfg.ProtocolMode != protocolModeV1 && cfg.ProtocolMode != protocolModeV2 {
403			return Result{}, fmt.Errorf("unsupported protocol mode %q", cfg.ProtocolMode)
404		}
405	
406		repo, err := git.Init(memory.NewStorage(), nil)
407		if err != nil {
408			return Result{}, fmt.Errorf("init in-memory repository: %w", err)
409		}
410	
411		stats := newStats(cfg.ShowStats)
412		sourceConn, err := newTransportConn(cfg.Source, "source", stats)
413		if err != nil {
414			return Result{}, fmt.Errorf("create source transport: %w", err)
415		}
416		targetConn, err := newTransportConn(cfg.Target, "target", stats)
417		if err != nil {
418			return Result{}, fmt.Errorf("create target transport: %w", err)
419		}
420	
421		sourceRefs, sourceService, err := listSourceRefs(ctx, sourceConn, cfg)
422		if err != nil {
423			return Result{}, fmt.Errorf("list source refs: %w", err)
424		}
425		targetAdv, err := advertisedRefsV1(ctx, targetConn, transport.ReceivePackServiceName)
426		if err != nil {
427			return Result{}, fmt.Errorf("list target refs: %w", err)
428		}
429		targetRefs, err := advertisedReferences(targetAdv)
430		if err != nil {
431			return Result{}, fmt.Errorf("decode target refs: %w", err)
432		}
433	
434		sourceRefMap := refHashMap(sourceRefs)
435		targetRefMap := refHashMap(targetRefs)
436	
437		desiredRefs, managedTargets, err := buildDesiredRefs(sourceRefMap, cfg)
438		if err != nil {
439			return Result{}, err
440		}
441		if len(desiredRefs) == 0 {
442			return Result{}, fmt.Errorf("no source refs matched")
443		}
444		if ok, reason := canBootstrapRelay(cfg, desiredRefs, targetRefMap); ok {
445			if cfg.DryRun {
446				plans, err := buildBootstrapPlans(desiredRefs, targetRefMap)
447				if err != nil {
448					return Result{}, err
449				}
450				return Result{
451					Plans:              plans,
452					DryRun:             true,
453					Relay:              false,
454					RelayMode:          "",
455					RelayReason:        reason,
456					BootstrapSuggested: true,
457					Stats:              stats.snapshot(),
458					Measurement:        measurementDone(),
459					Protocol:           sourceService.protocol,
460				}, nil
461			}
462			return bootstrapWithInputs(ctx, cfg, stats, sourceConn, targetConn, sourceService, targetAdv, desiredRefs, targetRefMap, reason)
463		}
464	
465		if err := sourceService.Fetch(ctx, repo, sourceConn, desiredRefs, targetRefMap); err != nil {
466			if !errors.Is(err, git.NoErrAlreadyUpToDate) {
467				return Result{}, err
468			}
469		}
470	
471		plans, err := buildPlans(repo, desiredRefs, targetRefMap, managedTargets, cfg)
472		if err != nil {
473			return Result{}, err
474		}
475	
476		result := Result{
477			Plans:       plans,
478			DryRun:      cfg.DryRun,
479			Relay:       false,
480			RelayMode:   "",
481			RelayReason: "",
482			Stats:       stats.snapshot(),
483			Measurement: measurementDone(),
484			Protocol:    sourceService.protocol,
485		}
486	
487		pushPlans := make([]BranchPlan, 0, len(plans))
488		for _, plan := range plans {
489			switch plan.Action {
490			case ActionCreate, ActionUpdate:
491				if cfg.DryRun {
492					result.Skipped++
493					continue
494				}
495				pushPlans = append(pushPlans, plan)
496			case ActionDelete:
497				if cfg.DryRun {
498					result.Skipped++
499					continue
500				}
501				pushPlans = append(pushPlans, plan)
502			case ActionSkip:
503				result.Skipped++
504			case ActionBlock:
505				result.Blocked++
506			}
507		}
508	
509		if !cfg.DryRun && result.Blocked > 0 {
510			return result, fmt.Errorf("blocked %d ref update(s); rerun with --force where appropriate", result.Blocked)
511		}
512		result.RelayReason = relayFallbackReason(cfg, pushPlans, targetAdv)
513	
514		if !cfg.DryRun {
515			if ok, reason := canIncrementalRelay(cfg, pushPlans, targetAdv); ok {
516				relayPlans := append([]BranchPlan(nil), pushPlans...)
517				desiredRelay := desiredSubsetForPlans(desiredRefs, relayPlans)
518				packReader, err := sourceService.FetchPack(ctx, sourceConn, desiredRelay, targetRefMap)
519				if err != nil {
520					return result, fmt.Errorf("fetch source pack: %w", err)
521				}
522				defer packReader.Close()
523				packReader = limitPackReadCloser(packReader, cfg.MaxPackBytes)
524				if err := pushPackToTarget(ctx, targetConn, targetAdv, relayPlans, packReader, cfg.Verbose); err != nil {
525					return result, fmt.Errorf("push target refs: %w", err)
526				}
527				result.Relay = true
528				result.RelayMode = "incremental"
529				result.RelayReason = reason
530			} else if ok, reason := canFullTagCreateRelay(pushPlans); ok {
531				relayPlans := append([]BranchPlan(nil), pushPlans...)
532				desiredRelay := desiredSubsetForPlans(desiredRefs, relayPlans)
533				packReader, err := sourceService.FetchPack(ctx, sourceConn, desiredRelay, nil)
534				if err != nil {
535					return result, fmt.Errorf("fetch source tag pack: %w", err)
536				}
537				defer packReader.Close()
538				packReader = limitPackReadCloser(packReader, cfg.MaxPackBytes)
539				if err := pushPackToTarget(ctx, targetConn, targetAdv, relayPlans, packReader, cfg.Verbose); err != nil {
540					return result, fmt.Errorf("push target refs: %w", err)
541				}
542				result.Relay = true
543				result.RelayMode = "incremental"
544				result.RelayReason = reason
545			} else if len(pushPlans) > 0 {
546				if err := ensureLocalObjectsForPush(ctx, repo, sourceConn, sourceService, desiredRefs, pushPlans); err != nil {
547					return result, fmt.Errorf("prepare local objects for push: %w", err)
548				}
549				if err := pushToTarget(ctx, repo, targetConn, targetAdv, pushPlans, targetRefMap, cfg.Verbose); err != nil {
550					return result, fmt.Errorf("push target refs: %w", err)
551				}
552			}
553		}
554	
555		for _, plan := range pushPlans {
556			switch plan.Action {
557			case ActionCreate, ActionUpdate:
558				result.Pushed++
559			case ActionDelete:
560				result.Deleted++
561			}
562		}
563	
564		result.Stats = stats.snapshot()
565		result.Measurement = measurementDone()
566		return result, nil
567	}
