626	func Probe(ctx context.Context, cfg Config) (ProbeResult, error) {
627		measurementDone := startMeasurement(cfg.MeasureMemory)
628		if cfg.ProtocolMode == "" {
629			cfg.ProtocolMode = protocolModeAuto
630		}
631		if cfg.ProtocolMode != protocolModeAuto && cfg.ProtocolMode != protocolModeV1 && cfg.ProtocolMode != protocolModeV2 {
632			return ProbeResult{}, fmt.Errorf("unsupported protocol mode %q", cfg.ProtocolMode)
633		}
634		if cfg.Source.URL == "" {
635			return ProbeResult{}, fmt.Errorf("source repository URL is required")
636		}
637	
638		stats := newStats(cfg.ShowStats)
639		sourceConn, err := newTransportConn(cfg.Source, "source", stats)
640		if err != nil {
641			return ProbeResult{}, fmt.Errorf("create source transport: %w", err)
642		}
643	
644		refs, service, err := listSourceRefs(ctx, sourceConn, cfg)
645		if err != nil {
646			return ProbeResult{}, fmt.Errorf("list source refs: %w", err)
647		}
648	
649		refInfos := make([]RefInfo, 0, len(refs))
650		for _, ref := range refs {
651			if ref.Type() != plumbing.HashReference {
652				continue
653			}
654			refInfos = append(refInfos, RefInfo{
655				Name: ref.Name().String(),
656				Hash: ref.Hash(),
657			})
658		}
659		sort.Slice(refInfos, func(i, j int) bool {
660			return refInfos[i].Name < refInfos[j].Name
661		})
662	
663		result := ProbeResult{
664			SourceURL:     cfg.Source.URL,
665			RequestedMode: cfg.ProtocolMode,
666			Protocol:      service.protocol,
667			RefPrefixes:   sourceRefPrefixes(cfg),
668			Capabilities:  sourceCapabilities(service),
669			Refs:          refInfos,
670			Stats:         stats.snapshot(),
671			Measurement:   measurementDone(),
672		}
673	
674		if cfg.Target.URL != "" {
675			targetConn, err := newTransportConn(cfg.Target, "target", stats)
676			if err != nil {
677				return ProbeResult{}, fmt.Errorf("create target transport: %w", err)
678			}
679			targetAdv, err := advertisedRefsV1(ctx, targetConn, transport.ReceivePackServiceName)
680			if err != nil {
681				return ProbeResult{}, fmt.Errorf("list target refs: %w", err)
682			}
683			result.TargetURL = cfg.Target.URL
684			result.TargetCaps = advCapabilities(targetAdv)
685			result.Stats = stats.snapshot()
686			result.Measurement = measurementDone()
687		}
688	
689		return result, nil
690	}
