475	func storeV2FetchPack(repo *git.Repository, r io.Reader) error {
476		reader := newPacketReader(r)
477		for {
478			kind, payload, err := reader.ReadPacket()
479			if err != nil {
480				if errors.Is(err, io.EOF) {
481					return nil
482				}
483				return fmt.Errorf("decode protocol v2 fetch response: %w", err)
484			}
485	
486			switch kind {
487			case packetTypeFlush:
488				return nil
489			case packetTypeDelim, packetTypeResponseEnd:
490				continue
491			case packetTypeData:
492				line := string(payload)
493				switch line {
494				case "packfile\n":
495					demux := sideband.NewDemuxer(sideband.Sideband64k, reader.Reader())
496					if err := packfile.UpdateObjectStorage(repo.Storer, demux); err != nil {
497						return fmt.Errorf("store source packfile: %w", err)
498					}
499					return nil
500				case "acknowledgments\n", "shallow-info\n":
501					if err := skipV2Section(reader); err != nil {
502						return err
503					}
504				default:
505					return fmt.Errorf("unexpected protocol v2 fetch section %q", strings.TrimSpace(line))
506				}
507			}
508		}
509	}
