511	func openV2FetchPackStream(body io.ReadCloser) (io.ReadCloser, error) {
512		reader := newPacketReader(body)
513		for {
514			kind, payload, err := reader.ReadPacket()
515			if err != nil {
516				if errors.Is(err, io.EOF) {
517					return nil, io.ErrUnexpectedEOF
518				}
519				return nil, fmt.Errorf("decode protocol v2 fetch response: %w", err)
520			}
521	
522			switch kind {
523			case packetTypeFlush:
524				return nil, io.ErrUnexpectedEOF
525			case packetTypeDelim, packetTypeResponseEnd:
526				continue
527			case packetTypeData:
528				line := string(payload)
529				switch line {
530				case "packfile\n":
531					return &wrappedReadCloser{
532						Reader: sideband.NewDemuxer(sideband.Sideband64k, reader.Reader()),
533						Closer: body,
534					}, nil
535				case "acknowledgments\n", "shallow-info\n":
536					if err := skipV2Section(reader); err != nil {
537						return nil, err
538					}
539				default:
540					return nil, fmt.Errorf("unexpected protocol v2 fetch section %q", strings.TrimSpace(line))
541				}
542			}
543		}
544	}
