546	func skipV2Section(reader *packetReader) error {
547		for {
548			kind, _, err := reader.ReadPacket()
549			if err != nil {
550				return err
551			}
552			if kind == packetTypeDelim || kind == packetTypeFlush {
553				return nil
554			}
