558	func decodeV2LSRefs(r io.Reader) ([]*plumbing.Reference, error) {
559		reader := newPacketReader(r)
560		var refs []*plumbing.Reference
561		for {
562			kind, payload, err := reader.ReadPacket()
563			if err != nil {
564				return nil, err
565			}
566			if kind == packetTypeFlush {
567				return refs, nil
568			}
569			if kind != packetTypeData {
570				return nil, fmt.Errorf("unexpected packet type %v in ls-refs response", kind)
571			}
572	
573			fields := strings.Fields(strings.TrimSpace(string(payload)))
574			if len(fields) < 2 {
575				return nil, fmt.Errorf("malformed ls-refs response line %q", payload)
576			}
577			hash := plumbing.NewHash(fields[0])
578			name := plumbing.ReferenceName(fields[1])
579			refs = append(refs, plumbing.NewHashReference(name, hash))
580		}
581	}
