583	func sourceRefPrefixes(cfg Config) []string {
584		prefixSet := map[string]struct{}{}
585	
586		addPrefix := func(ref plumbing.ReferenceName) {
587			switch {
588			case ref.IsBranch():
589				prefixSet["refs/heads/"] = struct{}{}
590			case ref.IsTag():
591				prefixSet["refs/tags/"] = struct{}{}
592			}
593		}
594	
595		if len(cfg.Mappings) > 0 {
596			for _, mapping := range cfg.Mappings {
597				sourceRef, _, _, err := normalizeMapping(mapping)
598				if err != nil {
599					continue
600				}
601				addPrefix(sourceRef)
602			}
603		} else {
604			prefixSet["refs/heads/"] = struct{}{}
605		}
606		if cfg.IncludeTags {
607			prefixSet["refs/tags/"] = struct{}{}
608		}
609	
610		prefixes := make([]string, 0, len(prefixSet))
611		for prefix := range prefixSet {
612			prefixes = append(prefixes, prefix)
613		}
614		sort.Strings(prefixes)
615		return prefixes
616	}
