952			cfg.BatchMaxPackBytes = batchLimit
953			progressf(
954				cfg.Verbose,
955				"bootstrap: github repo-size preflight selected batched mode with batch-max-pack-bytes=%d",
956				cfg.BatchMaxPackBytes,
957			)
958		}
959	
960		if cfg.BatchMaxPackBytes > 0 {
961			return bootstrapBatchedWithInputs(ctx, cfg, stats, sourceConn, targetConn, sourceService, targetAdv, plans, desiredRefs, targetRefs, result)
962		}
963	
964		progressf(cfg.Verbose, "bootstrap: fetching %d ref(s) from source", len(plans))
965	
966		packReader, err := sourceService.FetchPack(ctx, sourceConn, desiredRefs, nil)
967		if err != nil {
968			if errors.Is(err, git.NoErrAlreadyUpToDate) {
969				return result, nil
970			}
971			return result, fmt.Errorf("fetch source pack: %w", err)
972		}
973		packReader = limitPackReadCloser(packReader, cfg.MaxPackBytes)
974	
975		progressf(cfg.Verbose, "bootstrap: pushing %d ref(s) to target", len(plans))
976		pushErr := pushPackToTarget(ctx, targetConn, targetAdv, plans, packReader, cfg.Verbose)
977		if closeErr := packReader.Close(); closeErr != nil && pushErr == nil {
978			pushErr = closeErr
979		}
980		if pushErr != nil {
981			autoBatchSize, ok := autoBatchMaxPackBytes(cfg, sourceService, pushErr)
982			if !ok {
983				return result, fmt.Errorf("push target refs: %w", pushErr)
984			}
985			progressf(
986				cfg.Verbose,
987				"bootstrap: target rejected single-pack push; retrying with batch-max-pack-bytes=%d",
988				autoBatchSize,
989			)
990			cfg.BatchMaxPackBytes = autoBatchSize
991			return bootstrapBatchedWithInputs(ctx, cfg, stats, sourceConn, targetConn, sourceService, targetAdv, plans, desiredRefs, targetRefs, result)
992		}
993	
994		result.Pushed = len(plans)
995		result.Stats = stats.snapshot()
996		return result, nil
997	}
