999	func autoBatchMaxPackBytes(cfg Config, sourceService *sourceRefService, err error) (int64, bool) {
1000		if cfg.BatchMaxPackBytes > 0 || !isTargetBodyLimitError(err) {
1001			return 0, false
1002		}
1003		if sourceService == nil || sourceService.protocol != protocolModeV2 || !fetchCapabilitySupports(sourceService.v2, "filter") {
1004			return 0, false
1005		}
1006	
1007		batchLimit := int64(defaultAutoBatchMaxPackBytes)
1008		if targetLimit := targetBodyLimit(err); targetLimit > 0 {
1009			derivedLimit := targetLimit / 2
1010			if derivedLimit <= 0 {
1011				derivedLimit = targetLimit
1012			}
1013			if derivedLimit < batchLimit {
1014				batchLimit = derivedLimit
1015			}
1016		}
1017		if cfg.MaxPackBytes > 0 && cfg.MaxPackBytes < batchLimit {
1018			batchLimit = cfg.MaxPackBytes
1019		}
1020		if batchLimit <= 0 {
1021			return 0, false
1022		}
1023		return batchLimit, true
1024	}
