1029		}
1030		if sourceConn == nil || sourceConn.endpoint == nil {
1031			return 0, false
1032		}
1033		if sourceService == nil || sourceService.protocol != protocolModeV2 || !fetchCapabilitySupports(sourceService.v2, "filter") {
1034			return 0, false
1035		}
1036		repoSizeKB, ok := lookupGitHubRepoSizeKB(ctx, sourceConn)
