1051	func lookupGitHubRepoSizeKB(ctx context.Context, sourceConn *transportConn) (int64, bool) {
1052		owner, repo, ok := githubOwnerRepo(sourceConn)
1053		if !ok {
1054			return 0, false
1055		}
1056	
1057		apiURL := strings.TrimRight(githubRepoAPIBaseURL, "/") + "/repos/" + owner + "/" + repo
1058		req, err := http.NewRequestWithContext(ctx, http.MethodGet, apiURL, nil)
1059		if err != nil {
1060			return 0, false
1061		}
1062		req.Header.Set("Accept", "application/vnd.github+json")
1063		req.Header.Set("X-GitHub-Api-Version", "2022-11-28")
1064		req.Header.Set("User-Agent", capability.DefaultAgent())
1065		req.Header.Set(statsPhaseHdr, "github repo metadata")
1066	
1067		resp, err := sourceConn.http.Do(req)
1068		if err != nil {
1069			return 0, false
1070		}
1071		defer resp.Body.Close()
1072		if resp.StatusCode != http.StatusOK {
1073			return 0, false
1074		}
1075	
1076		var payload struct {
1077			Size int64 `json:"size"`
1078		}
1079		if err := json.NewDecoder(resp.Body).Decode(&payload); err != nil {
1080			return 0, false
1081		}
1082		if payload.Size <= 0 {
1083			return 0, false
1084		}
1085		return payload.Size, true
1086	}
