1088	func githubOwnerRepo(sourceConn *transportConn) (string, string, bool) {
1089		if sourceConn == nil || sourceConn.endpoint == nil {
1090			return "", "", false
1091		}
1092		ep := sourceConn.endpoint
1093		if ep.Protocol != "http" && ep.Protocol != "https" {
1094			return "", "", false
1095		}
1096		if !strings.EqualFold(ep.Host, "github.com") {
1097			return "", "", false
1098		}
1099	
1100		path := strings.Trim(ep.Path, "/")
1101		if strings.HasSuffix(path, ".git") {
1102			path = strings.TrimSuffix(path, ".git")
1103		}
1104		parts := strings.Split(path, "/")
1105		if len(parts) != 2 || parts[0] == "" || parts[1] == "" {
1106			return "", "", false
1107		}
1108		return parts[0], parts[1], true
1109	}
