1111	func isTargetBodyLimitError(err error) bool {
1112		if err == nil {
1113			return false
1114		}
1115		message := strings.ToLower(err.Error())
1116		return strings.Contains(message, "body exceeded size limit") ||
1117			(strings.Contains(message, "request body") && strings.Contains(message, "too large")) ||
1118			(strings.Contains(message, "payload") && strings.Contains(message, "too large")) ||
1119			strings.Contains(message, "http 413")
1120	}
