1122	func targetBodyLimit(err error) int64 {
1123		if err == nil {
1124			return 0
1125		}
1126		matches := bodyLimitPattern.FindStringSubmatch(strings.ToLower(err.Error()))
1127		if len(matches) != 2 {
1128			return 0
1129		}
1130		limit, parseErr := strconv.ParseInt(matches[1], 10, 64)
1131		if parseErr != nil {
1132			return 0
1133		}
1134		return limit
1135	}
