1144	func bootstrapBatchedWithInputs(
1145		ctx context.Context,
1146		cfg Config,
1147		stats *statsCollector,
1148		sourceConn *transportConn,
1149		targetConn *transportConn,
1150		sourceService *sourceRefService,
1151		targetAdv *packp.AdvRefs,
1152		plans []BranchPlan,
1153		desiredRefs map[plumbing.ReferenceName]desiredRef,
1154		targetRefs map[plumbing.ReferenceName]plumbing.Hash,
1155		result Result,
1156	) (Result, error) {
1157		if sourceService.protocol != protocolModeV2 {
1158			return result, fmt.Errorf("bootstrap batching currently requires protocol v2")
1159		}
1160		if !fetchCapabilitySupports(sourceService.v2, "filter") {
1161			return result, fmt.Errorf("bootstrap batching requires source fetch filter support")
1162		}
1163	
1164		planRefs := make([]desiredRef, 0, len(plans))
1165		tagPlans := make([]BranchPlan, 0, len(plans))
1166		tagDesired := make(map[plumbing.ReferenceName]desiredRef)
1167		for _, plan := range plans {
1168			if plan.Kind == RefKindTag {
1169				tagPlans = append(tagPlans, plan)
1170				if desired, ok := desiredRefs[plan.TargetRef]; ok {
1171					tagDesired[plan.TargetRef] = desired
1172				}
1173				continue
1174			}
1175			if !plan.SourceRef.IsBranch() || !plan.TargetRef.IsBranch() {
1176				return result, fmt.Errorf("bootstrap batching currently supports branch refs and create-only tags")
1177			}
1178			planRefs = append(planRefs, desiredRef{
1179				Kind:       plan.Kind,
1180				Label:      plan.Branch,
1181				SourceRef:  plan.SourceRef,
1182				TargetRef:  plan.TargetRef,
1183				SourceHash: plan.SourceHash,
1184			})
1185		}
1186	
1187		var (
1188			batches []bootstrapBatch
1189			err     error
1190		)
1191		if len(planRefs) > 0 {
1192			progressf(cfg.Verbose, "bootstrap-batch: planning checkpoints for %d branch ref(s)", len(planRefs))
1193			batches, err = planBootstrapBatches(ctx, cfg, sourceConn, sourceService, planRefs, targetRefs)
1194			if err != nil {
1195				return result, err
1196			}
1197		}
1198	
1199		batchLimit := cfg.BatchMaxPackBytes
1200		if cfg.MaxPackBytes > 0 && (batchLimit == 0 || cfg.MaxPackBytes < batchLimit) {
1201			batchLimit = cfg.MaxPackBytes
1202		}
1203	
1204		for _, batch := range batches {
1205			result.PlannedBatchCount += len(batch.Checkpoints)
1206			result.TempRefs = append(result.TempRefs, batch.TempRef.String())
1207			progressf(
1208				cfg.Verbose,
1209				"bootstrap-batch: branch=%s temp-ref=%s planned-batches=%d resume=%s",
1210				batch.Plan.TargetRef,
1211				batch.TempRef,
1212				len(batch.Checkpoints),
1213				shortHash(batch.ResumeHash),
1214			)
1215			current := batch.ResumeHash
1216			startIdx, err := bootstrapResumeIndex(batch.Checkpoints, batch.ResumeHash)
1217			if err != nil {
1218				return result, fmt.Errorf("resume bootstrap batch for %s: %w", batch.Plan.TargetRef, err)
1219			}
1220			for idx := startIdx; idx < len(batch.Checkpoints); idx++ {
1221				checkpoint := batch.Checkpoints[idx]
1222				progressf(
1223					cfg.Verbose,
1224					"bootstrap-batch: branch=%s batch=%d/%d from=%s to=%s",
1225					batch.Plan.TargetRef,
1226					idx+1,
1227					len(batch.Checkpoints),
1228					shortHash(current),
1229					shortHash(checkpoint),
1230				)
1231				stagePlans := []BranchPlan{
1232					{
1233						Branch:     batch.Plan.Branch,
1234						SourceRef:  batch.Plan.SourceRef,
1235						TargetRef:  batch.TempRef,
1236						SourceHash: checkpoint,
1237						TargetHash: current,
1238						Kind:       batch.Plan.Kind,
1239						Action:     actionForTargetHash(current),
1240						Reason:     fmt.Sprintf("%s -> %s via %s", shortHash(current), shortHash(checkpoint), batch.TempRef),
1241					},
1242				}
1243				if idx == len(batch.Checkpoints)-1 {
1244					stagePlans = append(stagePlans, BranchPlan{
1245						Branch:     batch.Plan.Branch,
1246						SourceRef:  batch.Plan.SourceRef,
1247						TargetRef:  batch.Plan.TargetRef,
1248						SourceHash: checkpoint,
1249						TargetHash: plumbing.ZeroHash,
1250						Kind:       batch.Plan.Kind,
1251						Action:     ActionCreate,
1252						Reason:     fmt.Sprintf("create %s at %s", batch.Plan.TargetRef, shortHash(checkpoint)),
1253					})
1254				}
1255	
1256				packReader, err := sourceService.FetchPack(ctx, sourceConn, singleDesiredRef(batch.Plan.SourceRef, batch.TempRef, checkpoint), singleHaveMap(current))
1257				if err != nil {
1258					return result, fmt.Errorf("fetch source batch pack for %s: %w", batch.Plan.TargetRef, err)
1259				}
1260				packReader = limitPackReadCloser(packReader, batchLimit)
1261				if err := pushPackToTarget(ctx, targetConn, targetAdv, stagePlans, packReader, cfg.Verbose); err != nil {
1262					return result, fmt.Errorf("push bootstrap batch for %s: %w", batch.Plan.TargetRef, err)
1263				}
1264				progressf(
1265					cfg.Verbose,
1266					"bootstrap-batch: branch=%s batch=%d/%d complete",
1267					batch.Plan.TargetRef,
1268					idx+1,
1269					len(batch.Checkpoints),
1270				)
1271				current = checkpoint
1272				result.BatchCount++
1273			}
1274	
1275			if current.IsZero() {
1276				return result, fmt.Errorf("bootstrap batching for %s completed with no checkpoint state", batch.Plan.TargetRef)
1277			}
1278			if batch.ResumeHash == batch.Plan.SourceHash {
1279				if err := pushCommandsToTarget(ctx, targetConn, targetAdv, []BranchPlan{{
1280					Branch:     batch.Plan.Branch,
1281					SourceRef:  batch.Plan.SourceRef,
1282					TargetRef:  batch.Plan.TargetRef,
1283					SourceHash: batch.Plan.SourceHash,
1284					TargetHash: plumbing.ZeroHash,
1285					Kind:       batch.Plan.Kind,
1286					Action:     ActionCreate,
1287					Reason:     fmt.Sprintf("create %s at %s", batch.Plan.TargetRef, shortHash(batch.Plan.SourceHash)),
1288				}}, cfg.Verbose); err != nil {
1289					return result, fmt.Errorf("resume bootstrap cutover for %s: %w", batch.Plan.TargetRef, err)
1290				}
1291			}
1292	
1293			deleteTempPlan := BranchPlan{
1294				Branch:     batch.Plan.Branch,
1295				TargetRef:  batch.TempRef,
1296				SourceHash: plumbing.ZeroHash,
1297				TargetHash: current,
1298				Kind:       batch.Plan.Kind,
1299				Action:     ActionDelete,
1300				Reason:     fmt.Sprintf("delete temp ref %s", batch.TempRef),
1301			}
1302			if err := pushCommandsToTarget(ctx, targetConn, targetAdv, []BranchPlan{deleteTempPlan}, cfg.Verbose); err != nil {
1303				return result, fmt.Errorf("delete bootstrap temp ref for %s: %w", batch.Plan.TargetRef, err)
1304			}
1305			progressf(cfg.Verbose, "bootstrap-batch: branch=%s finalized", batch.Plan.TargetRef)
1306		}
1307	
1308		if len(tagPlans) > 0 {
1309			progressf(cfg.Verbose, "bootstrap-batch: pushing %d tag(s) after branch batches", len(tagPlans))
1310			tagTargetRefs := copyRefHashMap(targetRefs)
1311			for _, batch := range batches {
1312				tagTargetRefs[batch.Plan.TargetRef] = batch.Plan.SourceHash
1313			}
1314			packReader, err := sourceService.FetchPack(ctx, sourceConn, tagDesired, tagTargetRefs)
1315			if err != nil {
1316				if !errors.Is(err, git.NoErrAlreadyUpToDate) {
1317					return result, fmt.Errorf("fetch bootstrap tag pack: %w", err)
1318				}
1319			} else {
1320				defer packReader.Close()
1321				packReader = limitPackReadCloser(packReader, cfg.MaxPackBytes)
1322				if err := pushPackToTarget(ctx, targetConn, targetAdv, tagPlans, packReader, cfg.Verbose); err != nil {
1323					return result, fmt.Errorf("push bootstrap tags: %w", err)
1324				}
1325			}
1326		}
1327	
1328		result.Pushed = len(plans)
1329		result.Batching = true
1330		result.RelayMode = "bootstrap-batch"
1331		result.Stats = stats.snapshot()
1332		return result, nil
1333	}
