1367	func planBootstrapBatches(
1368		ctx context.Context,
1369		cfg Config,
1370		sourceConn *transportConn,
1371		sourceService *sourceRefService,
1372		desired []desiredRef,
1373		targetRefs map[plumbing.ReferenceName]plumbing.Hash,
1374	) ([]bootstrapBatch, error) {
