1385					TargetRef:  ref.TargetRef,
1386					SourceHash: ref.SourceHash,
1387					Kind:       ref.Kind,
1388					Action:     ActionCreate,
1389				},
1390				TempRef:     bootstrapTempRef(ref.TargetRef),
