1396	}
1397	
1398	func planBootstrapBranchCheckpoints(
1399		ctx context.Context,
1400		cfg Config,
1401		sourceConn *transportConn,
1402		sourceService *sourceRefService,
1403		ref desiredRef,
1404	) ([]plumbing.Hash, error) {
1405		progressf(cfg.Verbose, "bootstrap-batch: fetching commit graph for %s", ref.TargetRef)
1406		graphRepo, err := git.Init(memory.NewStorage(), nil)
1407		if err != nil {
1408			return nil, fmt.Errorf("init bootstrap planning repository: %w", err)
1409		}
1410		if err := fetchSourceCommitGraphV2(ctx, graphRepo, sourceConn, sourceService.v2, ref); err != nil {
1411			return nil, fmt.Errorf("fetch bootstrap planning graph for %s: %w", ref.TargetRef, err)
1412		}
1413	
1414		chain, err := firstParentChain(graphRepo, ref.SourceHash)
1415		if err != nil {
1416			return nil, fmt.Errorf("walk first-parent chain for %s: %w", ref.TargetRef, err)
1417		}
1418		if len(chain) == 0 {
1419			return nil, fmt.Errorf("empty first-parent chain for %s", ref.TargetRef)
1420		}
1421	
1422		checkpoints := make([]plumbing.Hash, 0, len(chain))
1423		prevIdx := -1
1424		prevHash := plumbing.ZeroHash
1425		prevSpan := 0
1426		for prevIdx < len(chain)-1 {
1427			bestIdx, err := largestCheckpointUnderLimit(ctx, cfg, sourceConn, sourceService, ref, chain, prevIdx, prevHash, prevSpan)
1428			if err != nil {
1429				return nil, err
1430			}
1431			if bestIdx <= prevIdx {
1432				return nil, fmt.Errorf("could not find bootstrap checkpoint for %s under batch-max-pack-bytes=%d", ref.TargetRef, cfg.BatchMaxPackBytes)
1433			}
1434			prevSpan = bestIdx - prevIdx
1435			prevIdx = bestIdx
1436			prevHash = chain[bestIdx]
1437			checkpoints = append(checkpoints, prevHash)
1438			progressf(
1439				cfg.Verbose,
1440				"bootstrap-batch: branch=%s planned-checkpoint=%s selected=%d chain-len=%d",
1441				ref.TargetRef,
1442				shortHash(prevHash),
1443				len(checkpoints),
1444				len(chain),
1445			)
1446		}
1447		return checkpoints, nil
1448	}
1449	
1450	func largestCheckpointUnderLimit(
1451		ctx context.Context,
1452		cfg Config,
1453		sourceConn *transportConn,
1454		sourceService *sourceRefService,
1455		ref desiredRef,
1456		chain []plumbing.Hash,
1457		prevIdx int,
1458		prevHash plumbing.Hash,
1459		prevSpan int,
1460	) (int, error) {
1461		return sampledCheckpointUnderLimitByProbe(chain, prevIdx, prevSpan, func(idx int) (bool, error) {
1462			tooLarge, err := sourcePackExceedsLimit(ctx, sourceConn, sourceService, ref, chain[idx], prevHash, cfg.BatchMaxPackBytes)
1463			if err != nil {
1464				return false, fmt.Errorf("measure bootstrap batch for %s at %s: %w", ref.TargetRef, shortHash(chain[idx]), err)
1465			}
1466			if tooLarge {
1467				progressf(cfg.Verbose, "bootstrap-batch: sample %s exceeds limit=%d", shortHash(chain[idx]), cfg.BatchMaxPackBytes)
1468			} else {
1469				progressf(cfg.Verbose, "bootstrap-batch: sample %s fits limit=%d", shortHash(chain[idx]), cfg.BatchMaxPackBytes)
1470			}
1471			return tooLarge, nil
1472		})
1473	}
1474	
1475	func sampledCheckpointUnderLimitByProbe(
1476		chain []plumbing.Hash,
1477		prevIdx int,
1478		prevSpan int,
1479		probe func(idx int) (bool, error),
1480	) (int, error) {
1481		lo := prevIdx + 1
1482		hi := len(chain) - 1
1483		if lo > hi {
1484			return -1, nil
1485		}
1486	
1487		samples := sampledCheckpointCandidates(lo, hi, prevSpan)
1488		best := -1
1489		for _, idx := range samples {
1490			tooLarge, err := probe(idx)
1491			if err != nil {
1492				return -1, err
1493			}
1494			if tooLarge {
1495				continue
1496			}
1497			best = idx
1498			break
1499		}
1500		if best != -1 {
1501			return best, nil
1502		}
1503	
1504		if prevSpan > 1 {
1505			shrunk := prevSpan / 2
1506			if shrunk < 1 {
1507				shrunk = 1
1508			}
1509			idx := lo + shrunk - 1
1510			if idx > hi {
1511				idx = hi
1512			}
1513			if idx >= lo {
1514				tooLarge, err := probe(idx)
1515				if err != nil {
1516					return -1, err
1517				}
1518				if !tooLarge {
1519					return idx, nil
1520				}
1521			}
1522		}
1523	
1524		tooLarge, err := probe(lo)
1525		if err != nil {
1526			return -1, err
1527		}
1528		if tooLarge {
1529			return -1, nil
1530		}
1531		return lo, nil
1532	}
1533	
1534	func sampledCheckpointCandidates(lo, hi int, prevSpan int) []int {
1535		if lo > hi {
1536			return nil
1537		}
1538	
