1834			plan.Action = ActionSkip
1835			plan.Reason = fmt.Sprintf("%s already current", shortHash(want.SourceHash))
1836			return plan, nil
1837		}
1838	
1839		if want.Kind == RefKindTag {
1840			if force {
1841				plan.Action = ActionUpdate
1842				plan.Reason = fmt.Sprintf("%s -> %s (force tag update)", shortHash(targetHash), shortHash(want.SourceHash))
1843				return plan, nil
1844			}
1845			plan.Action = ActionBlock
