2262	func collectPushObjects(
2263		store storer.EncodedObjectStorer,
2264		hash plumbing.Hash,
2265		externalHaves map[plumbing.Hash]struct{},
2266		seen map[plumbing.Hash]bool,
2267		out *[]plumbing.Hash,
2268	) error {
2269		if hash.IsZero() {
2270			return nil
2271		}
2272		if _, ok := externalHaves[hash]; ok {
2273			return nil
2274		}
2275		if seen[hash] {
2276			return nil
2277		}
2278		seen[hash] = true
2279	
2280		obj, err := store.EncodedObject(plumbing.AnyObject, hash)
2281		if err != nil {
2282			return fmt.Errorf("load object %s: %w", hash, err)
2283		}
2284	
2285		switch obj.Type() {
2286		case plumbing.CommitObject:
2287			commit, err := object.GetCommit(store, hash)
2288			if err != nil {
2289				return fmt.Errorf("load commit %s: %w", hash, err)
2290			}
2291			if err := collectPushObjects(store, commit.TreeHash, externalHaves, seen, out); err != nil {
2292				return err
2293			}
2294			for _, parentHash := range commit.ParentHashes {
2295				if err := collectPushObjects(store, parentHash, externalHaves, seen, out); err != nil {
2296					return err
2297				}
2298			}
2299		case plumbing.TreeObject:
2300			tree, err := object.GetTree(store, hash)
2301			if err != nil {
2302				return fmt.Errorf("load tree %s: %w", hash, err)
2303			}
2304			for _, entry := range tree.Entries {
2305				if err := collectPushObjects(store, entry.Hash, externalHaves, seen, out); err != nil {
2306					return err
2307				}
2308			}
2309		case plumbing.TagObject:
2310			tag, err := object.GetTag(store, hash)
2311			if err != nil {
2312				return fmt.Errorf("load tag %s: %w", hash, err)
2313			}
2314			if err := collectPushObjects(store, tag.Target, externalHaves, seen, out); err != nil {
2315				return err
2316			}
2317		case plumbing.BlobObject:
2318		default:
2319			return fmt.Errorf("unsupported object type %s for %s", obj.Type(), hash)
2320		}
2321	
2322		*out = append(*out, hash)
2323		return nil
2324	}
