package gitproto

import (
	"bufio"
	"bytes"
	"encoding/hex"
	"fmt"
	"io"

	"github.com/go-git/go-git/v5/plumbing/format/pktline"
)

// PacketType represents the type of a pkt-line packet.
type PacketType int

const (
	PacketData        PacketType = iota
	PacketFlush                  // 0000
	PacketDelim                  // 0001
	PacketResponseEnd            // 0002
)

// PacketReader reads pkt-line formatted data. It reuses a fixed header buffer
// and a growable payload buffer to reduce allocations (issue #17).
type PacketReader struct {
	r      *bufio.Reader
	header [4]byte
	buf    []byte
}

func NewPacketReader(r io.Reader) *PacketReader {
	if br, ok := r.(*bufio.Reader); ok {
		return &PacketReader{r: br, buf: make([]byte, 0, 1024)}
	}
	return &PacketReader{r: bufio.NewReaderSize(r, 65536), buf: make([]byte, 0, 1024)}
}

// BufReader returns the underlying buffered reader for direct access
// (needed by sideband demuxer after switching to pack stream).
func (pr *PacketReader) BufReader() *bufio.Reader {
	return pr.r
}

// ReadPacket reads the next pkt-line packet. The returned payload slice is
// only valid until the next call to ReadPacket.
func (pr *PacketReader) ReadPacket() (PacketType, []byte, error) {
	if _, err := io.ReadFull(pr.r, pr.header[:]); err != nil {
		return PacketData, nil, err
	}

	switch string(pr.header[:]) {
	case "0000":
		return PacketFlush, nil, nil
	case "0001":
		return PacketDelim, nil, nil
	case "0002":
		return PacketResponseEnd, nil, nil
	}

	n, err := parseHexLength(pr.header)
	if err != nil {
		return PacketData, nil, err
	}
	if n <= 4 {
		return PacketData, nil, pktline.ErrInvalidPktLen
	}

	payloadLen := n - 4
	if payloadLen > cap(pr.buf) {
		pr.buf = make([]byte, payloadLen)
	} else {
		pr.buf = pr.buf[:payloadLen]
	}
	if _, err := io.ReadFull(pr.r, pr.buf); err != nil {
		return PacketData, nil, err
	}
	return PacketData, pr.buf, nil
}

func parseHexLength(header [4]byte) (int, error) {
	var n int
	for _, b := range header {
		v, ok := hexVal(b)
		if !ok {
			return 0, pktline.ErrInvalidPktLen
		}
		n = 16*n + int(v)
	}
	return n, nil
}

func hexVal(b byte) (byte, bool) {
	switch {
	case b >= '0' && b <= '9':
		return b - '0', true
	case b >= 'a' && b <= 'f':
		return b - 'a' + 10, true
	case b >= 'A' && b <= 'F':
		return b - 'A' + 10, true
	default:
		return 0, false
	}
}

// EncodeCommand builds a pkt-line encoded v2 command request.
func EncodeCommand(command string, capArgs, cmdArgs []string) ([]byte, error) {
	var buf bytes.Buffer
	enc := pktline.NewEncoder(&buf)
	if err := enc.EncodeString("command=" + command + "\n"); err != nil {
		return nil, err
	}
	for _, arg := range capArgs {
		if err := enc.EncodeString(arg + "\n"); err != nil {
			return nil, err
		}
	}
	if len(cmdArgs) > 0 {
		if _, err := buf.WriteString("0001"); err != nil {
			return nil, err
		}
		for _, arg := range cmdArgs {
			if err := enc.EncodeString(arg + "\n"); err != nil {
				return nil, err
			}
		}
	}
	if err := enc.Flush(); err != nil {
		return nil, err
	}
	return buf.Bytes(), nil
}

// SkipSection reads and discards packets until a delimiter or flush is reached.
func SkipSection(pr *PacketReader) error {
	for {
		kind, _, err := pr.ReadPacket()
		if err != nil {
			return err
		}
		if kind == PacketDelim || kind == PacketFlush {
			return nil
		}
	}
}

// HashHex is a helper to encode a 20-byte hash as lowercase hex.
func HashHex(h [20]byte) string {
	return hex.EncodeToString(h[:])
}

// FormatPktLine encodes a single pkt-line from a string payload.
func FormatPktLine(s string) string {
	n := len(s) + 4
	return fmt.Sprintf("%04x%s", n, s)
}

package gitproto

import (
	"fmt"
	"io"
	"sort"
	"strings"

	"github.com/go-git/go-git/v5/plumbing/protocol/packp/capability"
)

// V2Capabilities represents a parsed protocol v2 capability advertisement.
type V2Capabilities struct {
	Caps map[string]string
}

// Supports reports whether the server advertises the named capability.
func (c *V2Capabilities) Supports(name string) bool {
	if c == nil {
		return false
	}
	_, ok := c.Caps[name]
	return ok
}

// Value returns the value string for the named capability.
func (c *V2Capabilities) Value(name string) string {
	if c == nil {
		return ""
	}
	return c.Caps[name]
}

// FetchSupports checks whether a specific feature is listed in the
// "fetch" capability value (space-separated feature list).
func (c *V2Capabilities) FetchSupports(feature string) bool {
	if c == nil {
		return false
	}
	for _, f := range strings.Fields(c.Value("fetch")) {
		if f == feature {
			return true
		}
	}
	return false
}

// SortedKeys returns the capabilities as sorted "key" or "key=value" strings.
func (c *V2Capabilities) SortedKeys() []string {
	if c == nil {
		return nil
	}
	keys := make([]string, 0, len(c.Caps))
	for k, v := range c.Caps {
		if v == "" {
			keys = append(keys, k)
		} else {
			keys = append(keys, k+"="+v)
		}
	}
	sort.Strings(keys)
	return keys
}

// RequestCapabilities builds the capability arguments for a v2 command request.
func (c *V2Capabilities) RequestCapabilities() []string {
	var caps []string
	if agent := c.Value("agent"); agent != "" {
		caps = append(caps, "agent="+capability.DefaultAgent())
	}
	return caps
}

// DecodeV2Capabilities parses a protocol v2 capability advertisement from an
// info/refs response body.
func DecodeV2Capabilities(r io.Reader) (*V2Capabilities, error) {
	reader := NewPacketReader(r)

	// Skip service line and find "version 2\n"
	for {
		kind, payload, err := reader.ReadPacket()
		if err != nil {
			return nil, err
		}
		if kind == PacketFlush {
			continue
		}
		if kind != PacketData {
			return nil, fmt.Errorf("unexpected packet type %v before protocol advertisement", kind)
		}
		if strings.HasPrefix(string(payload), "# service=") {
			continue
		}
		if string(payload) != "version 2\n" {
			return nil, fmt.Errorf("unexpected protocol advertisement %q", payload)
		}
		break
	}

	caps := &V2Capabilities{Caps: make(map[string]string)}
	for {
		kind, payload, err := reader.ReadPacket()
		if err != nil {
			return nil, err
		}
		if kind == PacketFlush {
			return caps, nil
		}
		if kind != PacketData {
			return nil, fmt.Errorf("unexpected packet type %v in capability advertisement", kind)
		}
		line := strings.TrimSuffix(string(payload), "\n")
		name, value, _ := strings.Cut(line, "=")
		caps.Caps[name] = value
	}
}

// PreferredSideband returns the best sideband capability supported by the
// server. Prefers sideband-64k over sideband (issue #4: sideband preference
// was backwards in original code).
func PreferredSideband(caps *capability.List) capability.Capability {
	if caps.Supports(capability.Sideband64k) {
		return capability.Sideband64k
	}
	if caps.Supports(capability.Sideband) {
		return capability.Sideband
	}
	return ""
}

package gitproto

import (
	"bytes"
	"context"
	"crypto/tls"
	"fmt"
	"io"
	"net/http"

	"github.com/go-git/go-git/v5/plumbing/protocol/packp/capability"
	"github.com/go-git/go-git/v5/plumbing/transport"
	transporthttp "github.com/go-git/go-git/v5/plumbing/transport/http"
)

const statsPhaseHeader = "X-Git-Sync-Stats-Phase"

// Conn represents a connection to a remote Git HTTP endpoint.
type Conn struct {
	Label     string
	Endpoint  *transport.Endpoint
	Transport transport.Transport
	HTTP      *http.Client
	Auth      transport.AuthMethod
}

// NewConn creates a new connection to the given endpoint.
func NewConn(ep *transport.Endpoint, label string, auth transport.AuthMethod, rt http.RoundTripper) *Conn {
	httpClient := &http.Client{Transport: rt}
	return &Conn{
		Label:     label,
		Endpoint:  ep,
		Transport: transporthttp.NewClient(httpClient),
		HTTP:      httpClient,
		Auth:      auth,
	}
}

// NewHTTPTransport creates an http.Transport with optional TLS skip.
func NewHTTPTransport(skipTLS bool) http.RoundTripper {
	if !skipTLS {
		return http.DefaultTransport
	}
	if cloned, ok := http.DefaultTransport.(*http.Transport); ok {
		tc := cloned.Clone()
		if tc.TLSClientConfig == nil {
			tc.TLSClientConfig = &tls.Config{MinVersion: tls.VersionTLS12}
		}
		tc.TLSClientConfig.InsecureSkipVerify = true
		return tc
	}
	return http.DefaultTransport
}

// RequestInfoRefs fetches /info/refs for the given service.
func RequestInfoRefs(ctx context.Context, conn *Conn, service, gitProtocol string) ([]byte, error) {
	url := fmt.Sprintf("%s/info/refs?service=%s", conn.Endpoint.String(), service)
	req, err := http.NewRequestWithContext(ctx, http.MethodGet, url, nil)
	if err != nil {
		return nil, err
	}
	req.Header.Set("Accept", "*/*")
	req.Header.Set("User-Agent", capability.DefaultAgent())
	req.Header.Set(statsPhaseHeader, service+" info-refs")
	if gitProtocol != "" {
		req.Header.Set("Git-Protocol", gitProtocol)
	}
	ApplyAuth(req, conn.Auth)

	res, err := conn.HTTP.Do(req)
	if err != nil {
		return nil, err
	}
	defer res.Body.Close()
	if err := transporthttp.NewErr(res); err != nil {
		return nil, err
	}
	// Bound the read to prevent unbounded memory allocation (issue #9).
	const maxInfoRefsSize = 64 * 1024 * 1024 // 64 MiB
	lr := io.LimitReader(res.Body, maxInfoRefsSize+1)
	data, err := io.ReadAll(lr)
	if err != nil {
		return nil, err
	}
	if int64(len(data)) > maxInfoRefsSize {
		return nil, fmt.Errorf("info/refs response exceeds %d byte limit", maxInfoRefsSize)
	}
	return data, nil
}

// PostRPC sends a buffered POST to the given service and returns the full response body.
func PostRPC(ctx context.Context, conn *Conn, service string, body []byte, v2 bool, phase string) ([]byte, error) {
	reader, err := PostRPCStream(ctx, conn, service, body, v2, phase)
	if err != nil {
		return nil, err
	}
	defer reader.Close()
	return io.ReadAll(reader)
}

// PostRPCStream sends a POST to the given service and returns the response body
// as a streaming reader. Caller must close the returned ReadCloser.
func PostRPCStream(ctx context.Context, conn *Conn, service string, body []byte, v2 bool, phase string) (io.ReadCloser, error) {
	url := fmt.Sprintf("%s/%s", conn.Endpoint.String(), service)
	req, err := http.NewRequestWithContext(ctx, http.MethodPost, url, bytes.NewReader(body))
	if err != nil {
		return nil, err
	}
	req.Header.Set("Content-Type", fmt.Sprintf("application/x-%s-request", service))
	req.Header.Set("Accept", fmt.Sprintf("application/x-%s-result", service))
	req.Header.Set("User-Agent", capability.DefaultAgent())
	req.Header.Set(statsPhaseHeader, phase)
	if v2 {
		req.Header.Set("Git-Protocol", "version=2")
	}
	ApplyAuth(req, conn.Auth)

