		}
		switch kind {
		case PacketFlush:
			return nil, io.ErrUnexpectedEOF
		case PacketDelim, PacketResponseEnd:
			continue
		case PacketData:
			line := string(payload)
			switch line {
			case "packfile\n":
				return &wrappedRC{
					Reader: sideband.NewDemuxer(sideband.Sideband64k, reader.BufReader()),
					Closer: body,
				}, nil
			case "acknowledgments\n", "shallow-info\n":
				if err := SkipSection(reader); err != nil {
