package gitproto

import (
	"context"
	"fmt"
	"io"

	"github.com/go-git/go-git/v5/plumbing"
	"github.com/go-git/go-git/v5/plumbing/format/packfile"
	"github.com/go-git/go-git/v5/plumbing/protocol/packp"
	"github.com/go-git/go-git/v5/plumbing/protocol/packp/capability"
	"github.com/go-git/go-git/v5/plumbing/storer"
)

// PushCommand represents a single ref update command.
type PushCommand struct {
	Name   plumbing.ReferenceName
	Old    plumbing.Hash
	New    plumbing.Hash
	Delete bool
}

// PushObjects pushes locally-materialized objects to the target.
func PushObjects(
	ctx context.Context,
	conn *Conn,
	adv *packp.AdvRefs,
	commands []PushCommand,
	store storer.Storer,
	hashes []plumbing.Hash,
	verbose bool,
) error {
	session, err := conn.Transport.NewReceivePackSession(conn.Endpoint, conn.Auth)
	if err != nil {
		return fmt.Errorf("open target receive-pack session: %w", err)
	}
	defer session.Close()

	req := packp.NewReferenceUpdateRequestFromCapabilities(adv.Capabilities)
	req.Progress = progressWriter(verbose)
	if sb := PreferredSideband(adv.Capabilities); sb != "" {
		_ = req.Capabilities.Set(sb)
	}

	hasDelete := false
	hasUpdates := false
	for _, cmd := range commands {
		c := &packp.Command{Name: cmd.Name, Old: cmd.Old}
		if cmd.Delete {
			c.New = plumbing.ZeroHash
			hasDelete = true
		} else {
			c.New = cmd.New
			hasUpdates = true
		}
		req.Commands = append(req.Commands, c)
	}
	if hasDelete {
		if !adv.Capabilities.Supports(capability.DeleteRefs) {
			return fmt.Errorf("target does not support delete-refs")
		}
		_ = req.Capabilities.Set(capability.DeleteRefs)
	}

	return executePush(ctx, session, store, req, hashes, hasUpdates, !adv.Capabilities.Supports(capability.OFSDelta))
}

// PushPack pushes a pack stream (relay) to the target.
func PushPack(
	ctx context.Context,
	conn *Conn,
	adv *packp.AdvRefs,
	commands []PushCommand,
	pack io.ReadCloser,
	verbose bool,
) error {
	session, err := conn.Transport.NewReceivePackSession(conn.Endpoint, conn.Auth)
	if err != nil {
		return fmt.Errorf("open target receive-pack session: %w", err)
	}
	defer session.Close()

	req := packp.NewReferenceUpdateRequestFromCapabilities(adv.Capabilities)
	req.Progress = progressWriter(verbose)
	if sb := PreferredSideband(adv.Capabilities); sb != "" {
		_ = req.Capabilities.Set(sb)
	}

	for _, cmd := range commands {
		c := &packp.Command{Name: cmd.Name, Old: cmd.Old}
		if cmd.Delete {
			return fmt.Errorf("pack push only supports create and update actions")
		}
		c.New = cmd.New
		req.Commands = append(req.Commands, c)
	}

	req.Packfile = pack
	report, err := session.ReceivePack(ctx, req)
	if err != nil {
		_ = pack.Close()
		return err
	}
	if closeErr := pack.Close(); closeErr != nil {
		return closeErr
	}
	if report != nil {
		return report.Error()
	}
	return nil
}

// PushCommands sends ref update commands without a pack (for ref-only changes).
func PushCommands(
	ctx context.Context,
	conn *Conn,
	adv *packp.AdvRefs,
	commands []PushCommand,
	verbose bool,
) error {
	session, err := conn.Transport.NewReceivePackSession(conn.Endpoint, conn.Auth)
	if err != nil {
		return fmt.Errorf("open target receive-pack session: %w", err)
	}
	defer session.Close()

	req := packp.NewReferenceUpdateRequestFromCapabilities(adv.Capabilities)
	req.Progress = progressWriter(verbose)
	if sb := PreferredSideband(adv.Capabilities); sb != "" {
		_ = req.Capabilities.Set(sb)
	}

	hasDelete := false
	for _, cmd := range commands {
		c := &packp.Command{Name: cmd.Name, Old: cmd.Old}
		if cmd.Delete {
			c.New = plumbing.ZeroHash
			hasDelete = true
		} else {
			c.New = cmd.New
		}
		req.Commands = append(req.Commands, c)
	}
	if hasDelete {
		if !adv.Capabilities.Supports(capability.DeleteRefs) {
			return fmt.Errorf("target does not support delete-refs")
		}
		_ = req.Capabilities.Set(capability.DeleteRefs)
	}

	return executePush(ctx, session, nil, req, nil, false, false)
}

func executePush(
	ctx context.Context,
	session transport.ReceivePackSession,
	store storer.Storer,
	req *packp.ReferenceUpdateRequest,
	hashes []plumbing.Hash,
	sendPack bool,
	useRefDeltas bool,
) error {
	if !sendPack {
		report, err := session.ReceivePack(ctx, req)
		if err != nil {
			return err
		}
		if report != nil {
			return report.Error()
		}
		return nil
	}

	rd, wr := io.Pipe()
	req.Packfile = rd
	done := make(chan error, 1)

	go func() {
		enc := packfile.NewEncoder(wr, store, useRefDeltas)
		if _, err := enc.Encode(hashes, 10); err != nil {
			done <- wr.CloseWithError(err)
			return
		}
		done <- wr.Close()
	}()

	report, err := session.ReceivePack(ctx, req)
	if err != nil {
		_ = rd.Close()
		return err
	}
	if err := <-done; err != nil {
		return err
	}
	if report != nil {
		return report.Error()
	}
	return nil
}

// progressWriter returns os.Stderr if verbose, nil otherwise.
func progressWriter(verbose bool) io.Writer {
	if !verbose {
		return nil
	}
	// We import os here to return Stderr.
	return nil // Callers that need verbose output should use their own writers.
}

