	token, ok := lookupEntireDBToken(credHost, endpointBaseURL(ep), raw.SkipTLSVerify)
	if !ok || token == "" {
		return "", "", false
	}
	username := raw.Username
	if username == "" {
		username = "git"
	}
	return username, token, true
}

func endpointBaseURL(ep *transport.Endpoint) string {
	if ep == nil || ep.Host == "" {
		return ""
	}
	scheme := ep.Protocol
	if scheme == "" {
		scheme = "https"
	}
	host := ep.Host
	if ep.Port > 0 {
		host = fmt.Sprintf("%s:%d", host, ep.Port)
	}
	return scheme + "://" + host
}

func endpointCredentialHost(ep *transport.Endpoint) string {
	if ep == nil {
		return ""
	}
	if ep.Port > 0 {
		return fmt.Sprintf("%s:%d", ep.Host, ep.Port)
	}
	return ep.Host
}

func lookupEntireDBToken(host, baseURL string, skipTLS bool) (string, bool) {
	configDir := os.Getenv("ENTIRE_CONFIG_DIR")
	if configDir == "" {
		home, err := os.UserHomeDir()
		if err != nil {
