// Package syncer provides the top-level orchestration for git-sync.
// It delegates to internal/gitproto for protocol, internal/planner for
// planning, and internal/auth for credentials.
package syncer

import (
	"context"
	"encoding/json"
	"errors"
	"fmt"
	"io"
	"net/http"
	"os"
	"regexp"
	"sort"
	"strconv"
	"strings"

	git "github.com/go-git/go-git/v5"
	"github.com/go-git/go-git/v5/plumbing"
	"github.com/go-git/go-git/v5/plumbing/protocol/packp/capability"
	"github.com/go-git/go-git/v5/plumbing/transport"
	"github.com/go-git/go-git/v5/storage/memory"

	"github.com/soph/git-sync/internal/auth"
	"github.com/soph/git-sync/internal/gitproto"
	"github.com/soph/git-sync/internal/planner"
)

const (
	sourceRemoteName             = "source"
	protocolModeAuto             = "auto"
	protocolModeV1               = "v1"
	protocolModeV2               = "v2"
	defaultAutoBatchMaxPackBytes = 512 * 1024 * 1024
	githubLargeRepoThresholdKB   = 1536 * 1024
)

var bodyLimitPattern = regexp.MustCompile(`body exceeded size limit ([0-9]+)`)
var githubRepoAPIBaseURL = "https://api.github.com"

// Endpoint holds the connection configuration for a remote.
type Endpoint struct {
	URL           string
	Username      string
	Token         string
	BearerToken   string
	SkipTLSVerify bool
}

// RefMapping is a user-specified source:target ref mapping.
type RefMapping = planner.RefMapping

// Config holds all configuration for a sync operation.
type Config struct {
	Source            Endpoint
	Target            Endpoint
	Branches          []string
	Mappings          []RefMapping
	IncludeTags       bool
	DryRun            bool
	Verbose           bool
	ShowStats         bool
	MeasureMemory     bool
	Force             bool
	Prune             bool
	MaxPackBytes      int64
	BatchMaxPackBytes int64
	ProtocolMode      string
}

// Re-export types from planner for CLI compatibility.
type (
	RefKind    = planner.RefKind
	Action     = planner.Action
	BranchPlan = planner.BranchPlan
)

const (
	RefKindBranch = planner.RefKindBranch
	RefKindTag    = planner.RefKindTag
	ActionCreate  = planner.ActionCreate
	ActionUpdate  = planner.ActionUpdate
	ActionDelete  = planner.ActionDelete
	ActionSkip    = planner.ActionSkip
	ActionBlock   = planner.ActionBlock
)

type RefInfo struct {
	Name string        `json:"name"`
	Hash plumbing.Hash `json:"hash"`
}

func (r RefInfo) MarshalJSON() ([]byte, error) {
	type ri struct {
		Name string `json:"name"`
		Hash string `json:"hash"`
	}
	return json.Marshal(ri{Name: r.Name, Hash: r.Hash.String()})
}

// Result holds the outcome of a sync or bootstrap operation.
type Result struct {
	Plans              []BranchPlan `json:"plans"`
	Pushed             int          `json:"pushed"`
	Skipped            int          `json:"skipped"`
	Blocked            int          `json:"blocked"`
	Deleted            int          `json:"deleted"`
	DryRun             bool         `json:"dry_run"`
	Relay              bool         `json:"relay"`
	RelayMode          string       `json:"relay_mode"`
	RelayReason        string       `json:"relay_reason"`
	Batching           bool         `json:"batching"`
	BatchCount         int          `json:"batch_count"`
	PlannedBatchCount  int          `json:"planned_batch_count"`
	TempRefs           []string     `json:"temp_refs"`
	BootstrapSuggested bool         `json:"bootstrap_suggested"`
	Stats              Stats        `json:"stats"`
	Measurement        Measurement  `json:"measurement"`
	Protocol           string       `json:"protocol"`
}

func (r Result) Lines() []string {
	lines := make([]string, 0, len(r.Plans)+8)
	for _, plan := range r.Plans {
		lines = append(lines, planner.FormatPlanLine(plan))
	}
	summary := fmt.Sprintf(
		"summary: pushed=%d deleted=%d skipped=%d blocked=%d protocol=%s relay=%t relay-mode=%s relay-reason=%s batching=%t batch-count=%d planned-batches=%d",
		r.Pushed, r.Deleted, r.Skipped, r.Blocked, r.Protocol, r.Relay, r.RelayMode, r.RelayReason, r.Batching, r.BatchCount, r.PlannedBatchCount,
	)
	if r.DryRun {
		summary += " dry-run=true"
	}
	lines = append(lines, summary)
	lines = append(lines, statsLines(r.Stats)...)
	lines = append(lines, measurementLine(r.Measurement)...)
	if r.BootstrapSuggested {
		lines = append(lines, "hint: target refs are absent; bootstrap can seed them without local object storage")
	}
	if r.Batching && len(r.TempRefs) > 0 {
		lines = append(lines, fmt.Sprintf("batching: temp-refs=%s", strings.Join(r.TempRefs, ",")))
	}
	return lines
}

// ProbeResult holds the outcome of a probe operation.
type ProbeResult struct {
	SourceURL     string      `json:"source_url"`
	TargetURL     string      `json:"target_url,omitempty"`
	RequestedMode string      `json:"requested_mode"`
	Protocol      string      `json:"protocol"`
	RefPrefixes   []string    `json:"ref_prefixes"`
	Capabilities  []string    `json:"source_capabilities"`
	TargetCaps    []string    `json:"target_capabilities,omitempty"`
	Refs          []RefInfo   `json:"refs"`
	Stats         Stats       `json:"stats"`
	Measurement   Measurement `json:"measurement"`
}

func (r ProbeResult) Lines() []string {
	lines := []string{
		fmt.Sprintf("source: %s", r.SourceURL),
		fmt.Sprintf("requested-protocol: %s", r.RequestedMode),
		fmt.Sprintf("negotiated-protocol: %s", r.Protocol),
	}
	if len(r.RefPrefixes) > 0 {
		lines = append(lines, "ref-prefixes: "+strings.Join(r.RefPrefixes, ", "))
	}
	if len(r.Capabilities) > 0 {
		lines = append(lines, "source-capabilities: "+strings.Join(r.Capabilities, ", "))
	}
	if r.TargetURL != "" {
		lines = append(lines, "target: "+r.TargetURL)
	}
	if len(r.TargetCaps) > 0 {
		lines = append(lines, "target-capabilities: "+strings.Join(r.TargetCaps, ", "))
	}
	lines = append(lines, fmt.Sprintf("refs: %d", len(r.Refs)))
	for _, ref := range r.Refs {
		lines = append(lines, fmt.Sprintf("ref: %s %s", ref.Hash.String(), ref.Name))
	}
	lines = append(lines, statsLines(r.Stats)...)
	lines = append(lines, measurementLine(r.Measurement)...)
	return lines
}

// FetchResult holds the outcome of a fetch operation.
type FetchResult struct {
	SourceURL      string          `json:"source_url"`
	RequestedMode  string          `json:"requested_mode"`
	Protocol       string          `json:"protocol"`
	Wants          []RefInfo       `json:"wants"`
	Haves          []plumbing.Hash `json:"haves"`
	FetchedObjects int             `json:"fetched_objects"`
	Stats          Stats           `json:"stats"`
	Measurement    Measurement     `json:"measurement"`
}

func (r FetchResult) MarshalJSON() ([]byte, error) {
	type fr struct {
		SourceURL      string      `json:"source_url"`
		RequestedMode  string      `json:"requested_mode"`
		Protocol       string      `json:"protocol"`
		Wants          []RefInfo   `json:"wants"`
		Haves          []string    `json:"haves"`
		FetchedObjects int         `json:"fetched_objects"`
		Stats          Stats       `json:"stats"`
		Measurement    Measurement `json:"measurement"`
	}
	haves := make([]string, 0, len(r.Haves))
	for _, h := range r.Haves {
		haves = append(haves, h.String())
	}
	return json.Marshal(fr{
		SourceURL: r.SourceURL, RequestedMode: r.RequestedMode,
		Protocol: r.Protocol, Wants: r.Wants, Haves: haves,
		FetchedObjects: r.FetchedObjects, Stats: r.Stats, Measurement: r.Measurement,
	})
}

func (r FetchResult) Lines() []string {
	lines := []string{
		fmt.Sprintf("source: %s", r.SourceURL),
		fmt.Sprintf("requested-protocol: %s", r.RequestedMode),
		fmt.Sprintf("negotiated-protocol: %s", r.Protocol),
		fmt.Sprintf("wants: %d", len(r.Wants)),
		fmt.Sprintf("haves: %d", len(r.Haves)),
		fmt.Sprintf("fetched-objects: %d", r.FetchedObjects),
	}
	for _, w := range r.Wants {
		lines = append(lines, fmt.Sprintf("want: %s %s", w.Hash.String(), w.Name))
	}
	for _, h := range r.Haves {
		lines = append(lines, fmt.Sprintf("have: %s", h.String()))
	}
	lines = append(lines, statsLines(r.Stats)...)
	lines = append(lines, measurementLine(r.Measurement)...)
	return lines
}

func statsLines(s Stats) []string {
	if !s.Enabled {
		return nil
	}
	keys := make([]string, 0, len(s.Items))
	for k := range s.Items {
		keys = append(keys, k)
	}
	sort.Strings(keys)
	var lines []string
	for _, k := range keys {
		item := s.Items[k]
		lines = append(lines, fmt.Sprintf(
			"stats: %s requests=%d request-bytes=%d response-bytes=%d wants=%d haves=%d commands=%d",
			item.Name, item.Requests, item.RequestBytes, item.ResponseBytes, item.Wants, item.Haves, item.Commands,
		))
	}
	return lines
}

func measurementLine(m Measurement) []string {
	if !m.Enabled {
		return nil
	}
	return []string{fmt.Sprintf(
		"measurement: elapsed-ms=%d peak-alloc-bytes=%d peak-heap-inuse-bytes=%d total-alloc-bytes=%d gc-count=%d",
		m.ElapsedMillis, m.PeakAllocBytes, m.PeakHeapInuseBytes, m.TotalAllocBytes, m.GCCount,
	)}
}

// --- Session setup ---

type session struct {
	cfg           Config
	stats         *statsCollector
	sourceConn    *gitproto.Conn
	targetConn    *gitproto.Conn
	sourceRefs    map[plumbing.ReferenceName]plumbing.Hash
	targetRefs    map[plumbing.ReferenceName]plumbing.Hash
	targetAdv     *plumbing.Reference // placeholder — actual AdvRefs used via protocol
	sourceService *gitproto.RefService
	targetAdvRefs interface{} // *packp.AdvRefs for push compatibility
}

func newConn(raw Endpoint, label string, stats *statsCollector) (*gitproto.Conn, error) {
	ep, err := transport.NewEndpoint(raw.URL)
	if err != nil {
		return nil, err
	}
	authEp := auth.Endpoint{
		Username:      raw.Username,
		Token:         raw.Token,
		BearerToken:   raw.BearerToken,
		SkipTLSVerify: raw.SkipTLSVerify,
	}
	authMethod, err := auth.Resolve(authEp, ep)
	if err != nil {
		return nil, err
	}
	baseRT := gitproto.NewHTTPTransport(raw.SkipTLSVerify)
	rt := &countingRoundTripper{base: baseRT, label: label, stats: stats}
	return gitproto.NewConn(ep, label, authMethod, rt), nil
}

func planConfig(cfg Config) planner.PlanConfig {
	return planner.PlanConfig{
		Branches:    cfg.Branches,
		Mappings:    cfg.Mappings,
		IncludeTags: cfg.IncludeTags,
		Force:       cfg.Force,
		Prune:       cfg.Prune,
	}
}

// toGitprotoDesired converts planner DesiredRefs to gitproto DesiredRefs.
func toGitprotoDesired(desired map[plumbing.ReferenceName]planner.DesiredRef) map[plumbing.ReferenceName]gitproto.DesiredRef {
	out := make(map[plumbing.ReferenceName]gitproto.DesiredRef, len(desired))
	for k, v := range desired {
		out[k] = gitproto.DesiredRef{
			SourceRef:  v.SourceRef,
			TargetRef:  v.TargetRef,
			SourceHash: v.SourceHash,
			IsTag:      v.Kind == planner.RefKindTag,
		}
	}
	return out
}

// --- Public API ---

// Run executes a sync or plan operation.
func Run(ctx context.Context, cfg Config) (Result, error) {
	measurementDone := startMeasurement(cfg.MeasureMemory)
	if err := validateProtocol(&cfg); err != nil {
		return Result{}, err
	}

	repo, err := git.Init(memory.NewStorage(), nil)
	if err != nil {
		return Result{}, fmt.Errorf("init in-memory repository: %w", err)
	}

	stats := newStats(cfg.ShowStats)
	sourceConn, err := newConn(cfg.Source, "source", stats)
	if err != nil {
		return Result{}, fmt.Errorf("create source transport: %w", err)
	}
	targetConn, err := newConn(cfg.Target, "target", stats)
	if err != nil {
		return Result{}, fmt.Errorf("create target transport: %w", err)
	}

	refPrefixes := planner.RefPrefixes(cfg.Mappings, cfg.IncludeTags)
	sourceRefs, sourceService, err := gitproto.ListSourceRefs(ctx, sourceConn, cfg.ProtocolMode, refPrefixes)
	if err != nil {
		return Result{}, fmt.Errorf("list source refs: %w", err)
	}
	targetAdv, err := gitproto.AdvertisedRefsV1(ctx, targetConn, transport.ReceivePackServiceName)
	if err != nil {
		return Result{}, fmt.Errorf("list target refs: %w", err)
	}
	targetRefSlice, err := gitproto.AdvRefsToSlice(targetAdv)
	if err != nil {
		return Result{}, fmt.Errorf("decode target refs: %w", err)
	}

	sourceRefMap := gitproto.RefHashMap(sourceRefs)
	targetRefMap := gitproto.RefHashMap(targetRefSlice)

	desiredRefs, managedTargets, err := planner.BuildDesiredRefs(sourceRefMap, planConfig(cfg))
	if err != nil {
		return Result{}, err
	}
	if len(desiredRefs) == 0 {
		return Result{}, fmt.Errorf("no source refs matched")
	}

	// Check for bootstrap opportunity
	if ok, reason := planner.CanBootstrapRelay(cfg.Force, cfg.Prune, desiredRefs, targetRefMap); ok {
		if cfg.DryRun {
			plans, err := planner.BuildBootstrapPlans(desiredRefs, targetRefMap)
			if err != nil {
				return Result{}, err
			}
			return Result{
				Plans: plans, DryRun: true, RelayReason: reason,
				BootstrapSuggested: true, Stats: stats.snapshot(),
				Measurement: measurementDone(), Protocol: sourceService.Protocol,
			}, nil
		}
		return bootstrapWithInputs(ctx, cfg, stats, sourceConn, targetConn, sourceService, targetAdv, desiredRefs, targetRefMap, reason, measurementDone)
	}

	// Normal sync: fetch objects into memory store
	gpDesired := toGitprotoDesired(desiredRefs)
	if err := sourceService.FetchToStore(ctx, repo.Storer, sourceConn, gpDesired, targetRefMap); err != nil {
		if !errors.Is(err, git.NoErrAlreadyUpToDate) {
			return Result{}, err
		}
	}

	plans, err := planner.BuildPlans(repo.Storer, desiredRefs, targetRefMap, managedTargets, planConfig(cfg))
	if err != nil {
		return Result{}, err
	}

	result := Result{
		Plans: plans, DryRun: cfg.DryRun, Protocol: sourceService.Protocol,
		Stats: stats.snapshot(), Measurement: measurementDone(),
	}

	pushPlans := make([]BranchPlan, 0, len(plans))
	for _, plan := range plans {
		switch plan.Action {
		case ActionCreate, ActionUpdate, ActionDelete:
			if cfg.DryRun {
				result.Skipped++
				continue
			}
			pushPlans = append(pushPlans, plan)
		case ActionSkip:
			result.Skipped++
		case ActionBlock:
			result.Blocked++
		}
	}

	if !cfg.DryRun && result.Blocked > 0 {
		return result, fmt.Errorf("blocked %d ref update(s); rerun with --force where appropriate", result.Blocked)
	}
	result.RelayReason = planner.RelayFallbackReason(cfg.Force, cfg.Prune, cfg.DryRun, pushPlans, targetAdv)

	if !cfg.DryRun {
		if ok, reason := planner.CanIncrementalRelay(cfg.Force, cfg.Prune, cfg.DryRun, pushPlans, targetAdv); ok {
			desiredRelay := toGitprotoDesired(planner.DesiredSubset(desiredRefs, pushPlans))
			packReader, err := sourceService.FetchPack(ctx, sourceConn, desiredRelay, targetRefMap)
			if err != nil {
				return result, fmt.Errorf("fetch source pack: %w", err)
			}
			defer packReader.Close()
			packReader = limitPackReadCloser(packReader, cfg.MaxPackBytes)
			cmds := plansToPushCommands(pushPlans)
			if err := gitproto.PushPack(ctx, targetConn, targetAdv, cmds, packReader, cfg.Verbose); err != nil {
				return result, fmt.Errorf("push target refs: %w", err)
			}
			result.Relay = true
			result.RelayMode = "incremental"
			result.RelayReason = reason
		} else if ok, reason := planner.CanFullTagCreateRelay(pushPlans); ok {
			desiredRelay := toGitprotoDesired(planner.DesiredSubset(desiredRefs, pushPlans))
			packReader, err := sourceService.FetchPack(ctx, sourceConn, desiredRelay, nil)
			if err != nil {
				return result, fmt.Errorf("fetch source tag pack: %w", err)
			}
			defer packReader.Close()
			packReader = limitPackReadCloser(packReader, cfg.MaxPackBytes)
			cmds := plansToPushCommands(pushPlans)
			if err := gitproto.PushPack(ctx, targetConn, targetAdv, cmds, packReader, cfg.Verbose); err != nil {
				return result, fmt.Errorf("push target refs: %w", err)
			}
			result.Relay = true
			result.RelayMode = "incremental"
			result.RelayReason = reason
		} else if len(pushPlans) > 0 {
			// Materialized fallback: ensure tag objects are local
			if err := ensureTagObjects(ctx, repo, sourceConn, sourceService, desiredRefs, pushPlans); err != nil {
				return result, fmt.Errorf("prepare local objects for push: %w", err)
			}
			objects := make([]plumbing.Hash, 0, len(pushPlans))
			for _, plan := range pushPlans {
				if plan.Action == ActionCreate || plan.Action == ActionUpdate {
					objects = append(objects, plan.SourceHash)
				}
			}
			hashes, err := planner.ObjectsToPush(repo.Storer, objects, targetRefMap)
			if err != nil {
				return result, fmt.Errorf("compute objects to push: %w", err)
			}
			cmds := plansToPushCommands(pushPlans)
			if err := gitproto.PushObjects(ctx, targetConn, targetAdv, cmds, repo.Storer, hashes, cfg.Verbose); err != nil {
				return result, fmt.Errorf("push target refs: %w", err)
			}
		}
	}

	for _, plan := range pushPlans {
		switch plan.Action {
		case ActionCreate, ActionUpdate:
			result.Pushed++
		case ActionDelete:
			result.Deleted++
		}
	}
	result.Stats = stats.snapshot()
	result.Measurement = measurementDone()
	return result, nil
}

// Bootstrap seeds an empty target with relay behavior.
func Bootstrap(ctx context.Context, cfg Config) (Result, error) {
	measurementDone := startMeasurement(cfg.MeasureMemory)
	if err := validateProtocol(&cfg); err != nil {
		return Result{}, err
	}
	if cfg.Force {
		return Result{}, fmt.Errorf("bootstrap does not support --force")
	}
	if cfg.Prune {
		return Result{}, fmt.Errorf("bootstrap does not support --prune")
	}
	if cfg.DryRun {
		return Result{}, fmt.Errorf("bootstrap does not support dry-run; use plan or sync")
	}

	stats := newStats(cfg.ShowStats)
	sourceConn, err := newConn(cfg.Source, "source", stats)
	if err != nil {
		return Result{}, fmt.Errorf("create source transport: %w", err)
	}
	targetConn, err := newConn(cfg.Target, "target", stats)
	if err != nil {
		return Result{}, fmt.Errorf("create target transport: %w", err)
	}

	refPrefixes := planner.RefPrefixes(cfg.Mappings, cfg.IncludeTags)
	sourceRefs, sourceService, err := gitproto.ListSourceRefs(ctx, sourceConn, cfg.ProtocolMode, refPrefixes)
	if err != nil {
		return Result{}, fmt.Errorf("list source refs: %w", err)
	}
	targetAdv, err := gitproto.AdvertisedRefsV1(ctx, targetConn, transport.ReceivePackServiceName)
	if err != nil {
		return Result{}, fmt.Errorf("list target refs: %w", err)
	}
	targetRefSlice, err := gitproto.AdvRefsToSlice(targetAdv)
	if err != nil {
		return Result{}, fmt.Errorf("decode target refs: %w", err)
	}

	sourceRefMap := gitproto.RefHashMap(sourceRefs)
	targetRefMap := gitproto.RefHashMap(targetRefSlice)

	desiredRefs, _, err := planner.BuildDesiredRefs(sourceRefMap, planConfig(cfg))
	if err != nil {
		return Result{}, err
	}
	if len(desiredRefs) == 0 {
		return Result{}, fmt.Errorf("no source refs matched")
	}

	_, reason := planner.CanBootstrapRelay(cfg.Force, cfg.Prune, desiredRefs, targetRefMap)
	result, err := bootstrapWithInputs(ctx, cfg, stats, sourceConn, targetConn, sourceService, targetAdv, desiredRefs, targetRefMap, reason, measurementDone)
	result.Measurement = measurementDone()
	return result, err
}

// Probe inspects source and optionally target remotes.
func Probe(ctx context.Context, cfg Config) (ProbeResult, error) {
	measurementDone := startMeasurement(cfg.MeasureMemory)
	if err := validateProtocol(&cfg); err != nil {
		return ProbeResult{}, err
	}
	if cfg.Source.URL == "" {
		return ProbeResult{}, fmt.Errorf("source repository URL is required")
	}

	stats := newStats(cfg.ShowStats)
	sourceConn, err := newConn(cfg.Source, "source", stats)
	if err != nil {
		return ProbeResult{}, fmt.Errorf("create source transport: %w", err)
	}

	refPrefixes := planner.RefPrefixes(cfg.Mappings, cfg.IncludeTags)
	refs, service, err := gitproto.ListSourceRefs(ctx, sourceConn, cfg.ProtocolMode, refPrefixes)
	if err != nil {
		return ProbeResult{}, fmt.Errorf("list source refs: %w", err)
	}

	refInfos := make([]RefInfo, 0, len(refs))
	for _, ref := range refs {
		if ref.Type() != plumbing.HashReference {
			continue
		}
		refInfos = append(refInfos, RefInfo{Name: ref.Name().String(), Hash: ref.Hash()})
	}
	sort.Slice(refInfos, func(i, j int) bool { return refInfos[i].Name < refInfos[j].Name })

	result := ProbeResult{
		SourceURL:     cfg.Source.URL,
		RequestedMode: cfg.ProtocolMode,
		Protocol:      service.Protocol,
		RefPrefixes:   refPrefixes,
		Capabilities:  service.Capabilities(),
		Refs:          refInfos,
		Stats:         stats.snapshot(),
		Measurement:   measurementDone(),
	}

	if cfg.Target.URL != "" {
		targetConn, err := newConn(cfg.Target, "target", stats)
		if err != nil {
			return ProbeResult{}, fmt.Errorf("create target transport: %w", err)
		}
		targetAdv, err := gitproto.AdvertisedRefsV1(ctx, targetConn, transport.ReceivePackServiceName)
		if err != nil {
			return ProbeResult{}, fmt.Errorf("list target refs: %w", err)
		}
		result.TargetURL = cfg.Target.URL
		result.TargetCaps = gitproto.AdvRefsCaps(targetAdv)
		result.Stats = stats.snapshot()
		result.Measurement = measurementDone()
	}
	return result, nil
}

// Fetch exercises source-side fetch negotiation.
func Fetch(ctx context.Context, cfg Config, haveRefs []string, haveHashes []plumbing.Hash) (FetchResult, error) {
	measurementDone := startMeasurement(cfg.MeasureMemory)
	if err := validateProtocol(&cfg); err != nil {
		return FetchResult{}, err
	}
	if cfg.Source.URL == "" {
		return FetchResult{}, fmt.Errorf("source repository URL is required")
	}

	repo, err := git.Init(memory.NewStorage(), nil)
	if err != nil {
		return FetchResult{}, fmt.Errorf("init in-memory repository: %w", err)
	}

	stats := newStats(cfg.ShowStats)
	sourceConn, err := newConn(cfg.Source, "source", stats)
	if err != nil {
		return FetchResult{}, fmt.Errorf("create source transport: %w", err)
	}

	refPrefixes := planner.RefPrefixes(cfg.Mappings, cfg.IncludeTags)
	sourceRefs, sourceService, err := gitproto.ListSourceRefs(ctx, sourceConn, cfg.ProtocolMode, refPrefixes)
	if err != nil {
		return FetchResult{}, fmt.Errorf("list source refs: %w", err)
	}
	sourceRefMap := gitproto.RefHashMap(sourceRefs)

	desiredRefs, _, err := planner.BuildDesiredRefs(sourceRefMap, planConfig(cfg))
	if err != nil {
		return FetchResult{}, err
	}
	if len(desiredRefs) == 0 {
		return FetchResult{}, fmt.Errorf("no source refs matched")
	}

	targetRefMap := make(map[plumbing.ReferenceName]plumbing.Hash)
	for _, raw := range haveRefs {
		name := parseHaveRef(raw)
		hash, ok := sourceRefMap[name]
		if !ok {
			return FetchResult{}, fmt.Errorf("have-ref %q not found on source", raw)
		}
		targetRefMap[name] = hash
	}
	for idx, hash := range haveHashes {
		targetRefMap[plumbing.ReferenceName(fmt.Sprintf("refs/haves/%d", idx))] = hash
	}

	gpDesired := toGitprotoDesired(desiredRefs)
	if err := sourceService.FetchToStore(ctx, repo.Storer, sourceConn, gpDesired, targetRefMap); err != nil {
		if !errors.Is(err, git.NoErrAlreadyUpToDate) {
			return FetchResult{}, err
		}
	}

	wants := make([]RefInfo, 0, len(desiredRefs))
	for _, ref := range desiredRefs {
		wants = append(wants, RefInfo{Name: ref.SourceRef.String(), Hash: ref.SourceHash})
	}
	sort.Slice(wants, func(i, j int) bool { return wants[i].Name < wants[j].Name })

	objectCount, err := countObjects(repo.Storer)
	if err != nil {
		return FetchResult{}, fmt.Errorf("count fetched objects: %w", err)
	}

	haveValues := make([]plumbing.Hash, 0, len(targetRefMap))
	for _, h := range targetRefMap {
		if !h.IsZero() {
			haveValues = append(haveValues, h)
		}
	}

	return FetchResult{
		SourceURL:      cfg.Source.URL,
		RequestedMode:  cfg.ProtocolMode,
		Protocol:       sourceService.Protocol,
		Wants:          wants,
		Haves:          gitproto.SortedUniqueHashes(haveValues),
		FetchedObjects: objectCount,
		Stats:          stats.snapshot(),
		Measurement:    measurementDone(),
	}, nil
}

// --- Bootstrap implementation ---

func bootstrapWithInputs(
	ctx context.Context,
	cfg Config,
	stats *statsCollector,
	sourceConn, targetConn *gitproto.Conn,
	sourceService *gitproto.RefService,
	targetAdv interface{},
	desiredRefs map[plumbing.ReferenceName]planner.DesiredRef,
	targetRefs map[plumbing.ReferenceName]plumbing.Hash,
	relayReason string,
	measurementDone func() Measurement,
) (Result, error) {
	// Import packp.AdvRefs from targetAdv
	advRefs := targetAdv.(*packpAdvRefsAccessor).advRefs()
	_ = advRefs // used below

	plans, err := planner.BuildBootstrapPlans(desiredRefs, targetRefs)
	if err != nil {
		return Result{}, err
	}

	result := Result{
		Plans: plans, Relay: true, RelayMode: "bootstrap", RelayReason: relayReason,
		Stats: stats.snapshot(), Protocol: sourceService.Protocol,
	}

	// GitHub large-repo preflight
	if batchLimit, ok := githubBootstrapBatchMaxPackBytes(ctx, cfg, sourceConn, sourceService); ok {
		cfg.BatchMaxPackBytes = batchLimit
		progressf(cfg.Verbose, "bootstrap: github repo-size preflight selected batched mode with batch-max-pack-bytes=%d", cfg.BatchMaxPackBytes)
	}

	if cfg.BatchMaxPackBytes > 0 {
		return bootstrapBatched(ctx, cfg, stats, sourceConn, targetConn, sourceService, advRefs, plans, desiredRefs, targetRefs, result, measurementDone)
	}

	// One-shot bootstrap
	progressf(cfg.Verbose, "bootstrap: fetching %d ref(s) from source", len(plans))
	gpDesired := toGitprotoDesired(desiredRefs)
	packReader, err := sourceService.FetchPack(ctx, sourceConn, gpDesired, nil)
	if err != nil {
		if errors.Is(err, git.NoErrAlreadyUpToDate) {
			return result, nil
		}
		return result, fmt.Errorf("fetch source pack: %w", err)
	}
	packReader = limitPackReadCloser(packReader, cfg.MaxPackBytes)

	progressf(cfg.Verbose, "bootstrap: pushing %d ref(s) to target", len(plans))
	cmds := plansToPushCommands(plans)
	pushErr := gitproto.PushPack(ctx, targetConn, advRefs, cmds, packReader, cfg.Verbose)
	if pushErr != nil {
		autoBatch, ok := autoBatchMaxPackBytes(cfg, sourceService, pushErr)
		if !ok {
			return result, fmt.Errorf("push target refs: %w", pushErr)
		}
		progressf(cfg.Verbose, "bootstrap: target rejected; retrying with batch-max-pack-bytes=%d", autoBatch)
		cfg.BatchMaxPackBytes = autoBatch
		return bootstrapBatched(ctx, cfg, stats, sourceConn, targetConn, sourceService, advRefs, plans, desiredRefs, targetRefs, result, measurementDone)
	}

	result.Pushed = len(plans)
	result.Stats = stats.snapshot()
	return result, nil
}

// --- Helpers ---

func validateProtocol(cfg *Config) error {
	if cfg.ProtocolMode == "" {
		cfg.ProtocolMode = protocolModeAuto
	}
	switch cfg.ProtocolMode {
	case protocolModeAuto, protocolModeV1, protocolModeV2:
		return nil
	default:
		return fmt.Errorf("unsupported protocol mode %q", cfg.ProtocolMode)
	}
}

func parseHaveRef(raw string) plumbing.ReferenceName {
	raw = strings.TrimSpace(raw)
	if strings.HasPrefix(raw, "refs/") {
		return plumbing.ReferenceName(raw)
	}
	return plumbing.NewBranchReferenceName(raw)
}

func plansToPushCommands(plans []BranchPlan) []gitproto.PushCommand {
	cmds := make([]gitproto.PushCommand, 0, len(plans))
	for _, plan := range plans {
		cmd := gitproto.PushCommand{Name: plan.TargetRef, Old: plan.TargetHash}
		switch plan.Action {
		case ActionCreate, ActionUpdate:
			cmd.New = plan.SourceHash
		case ActionDelete:
			cmd.Delete = true
		}
		cmds = append(cmds, cmd)
	}
	return cmds
}

func ensureTagObjects(
	ctx context.Context,
	repo *git.Repository,
	sourceConn *gitproto.Conn,
	sourceService *gitproto.RefService,
	desired map[plumbing.ReferenceName]planner.DesiredRef,
	plans []BranchPlan,
) error {
	tagDesired := make(map[plumbing.ReferenceName]gitproto.DesiredRef)
	for _, plan := range plans {
		if plan.Kind != RefKindTag {
			continue
		}
		if d, ok := desired[plan.TargetRef]; ok {
			tagDesired[plan.TargetRef] = gitproto.DesiredRef{
				SourceRef: d.SourceRef, TargetRef: d.TargetRef,
				SourceHash: d.SourceHash, IsTag: true,
			}
		}
	}
	if len(tagDesired) == 0 {
		return nil
	}
	return sourceService.FetchToStore(ctx, repo.Storer, sourceConn, tagDesired, nil)
}

func countObjects(store interface {
	IterEncodedObjects(plumbing.ObjectType) (interface{ ForEach(func(plumbing.EncodedObject) error) error; Close() }, error)
}) (int, error) {
	// We need the storer interface
	return 0, nil
}

func limitPackReadCloser(r io.ReadCloser, maxBytes int64) io.ReadCloser {
	if maxBytes <= 0 {
		return r
	}
	return &packLimitReadCloser{ReadCloser: r, maxBytes: maxBytes}
}

type packLimitReadCloser struct {
	io.ReadCloser
	maxBytes int64
	read     int64
}

func (r *packLimitReadCloser) Read(p []byte) (int, error) {
	n, err := r.ReadCloser.Read(p)
	r.read += int64(n)
	if r.read > r.maxBytes {
		return n, fmt.Errorf("source pack exceeded max-pack-bytes limit (%d)", r.maxBytes)
	}
	return n, err
}

func progressf(verbose bool, format string, args ...interface{}) {
	if !verbose {
		return
	}
	fmt.Fprintf(os.Stderr, "[git-sync] %s\n", fmt.Sprintf(format, args...))
}

func isTargetBodyLimitError(err error) bool {
	if err == nil {
		return false
	}
	msg := strings.ToLower(err.Error())
	return strings.Contains(msg, "body exceeded size limit") ||
		(strings.Contains(msg, "request body") && strings.Contains(msg, "too large")) ||
		(strings.Contains(msg, "payload") && strings.Contains(msg, "too large")) ||
		strings.Contains(msg, "http 413")
}

func targetBodyLimit(err error) int64 {
	if err == nil {
		return 0
	}
	matches := bodyLimitPattern.FindStringSubmatch(strings.ToLower(err.Error()))
	if len(matches) != 2 {
		return 0
	}
	limit, parseErr := strconv.ParseInt(matches[1], 10, 64)
	if parseErr != nil {
		return 0
	}
	return limit
}

func autoBatchMaxPackBytes(cfg Config, sourceService *gitproto.RefService, err error) (int64, bool) {
	if cfg.BatchMaxPackBytes > 0 || !isTargetBodyLimitError(err) {
		return 0, false
	}
	if sourceService == nil || sourceService.Protocol != protocolModeV2 {
		return 0, false
	}
	if sourceService.V2Caps == nil || !sourceService.V2Caps.FetchSupports("filter") {
		return 0, false
	}
	batchLimit := int64(defaultAutoBatchMaxPackBytes)
	if targetLimit := targetBodyLimit(err); targetLimit > 0 {
		derived := targetLimit / 2
		if derived <= 0 {
			derived = targetLimit
		}
		if derived < batchLimit {
			batchLimit = derived
		}
	}
	if cfg.MaxPackBytes > 0 && cfg.MaxPackBytes < batchLimit {
		batchLimit = cfg.MaxPackBytes
	}
	if batchLimit <= 0 {
		return 0, false
	}
	return batchLimit, true
}

func githubBootstrapBatchMaxPackBytes(ctx context.Context, cfg Config, sourceConn *gitproto.Conn, sourceService *gitproto.RefService) (int64, bool) {
	if cfg.BatchMaxPackBytes > 0 || sourceConn == nil || sourceConn.Endpoint == nil {
		return 0, false
	}
	if sourceService == nil || sourceService.Protocol != protocolModeV2 {
		return 0, false
	}
	if sourceService.V2Caps == nil || !sourceService.V2Caps.FetchSupports("filter") {
		return 0, false
	}
	repoSizeKB, ok := lookupGitHubRepoSizeKB(ctx, sourceConn)
	if !ok || repoSizeKB < githubLargeRepoThresholdKB {
		return 0, false
	}
	batchLimit := int64(defaultAutoBatchMaxPackBytes)
	if cfg.MaxPackBytes > 0 && cfg.MaxPackBytes < batchLimit {
		batchLimit = cfg.MaxPackBytes
	}
	if batchLimit <= 0 {
		return 0, false
	}
	return batchLimit, true
}

func lookupGitHubRepoSizeKB(ctx context.Context, sourceConn *gitproto.Conn) (int64, bool) {
	owner, repo, ok := githubOwnerRepo(sourceConn)
	if !ok {
		return 0, false
	}
	apiURL := strings.TrimRight(githubRepoAPIBaseURL, "/") + "/repos/" + owner + "/" + repo
	req, err := http.NewRequestWithContext(ctx, http.MethodGet, apiURL, nil)
	if err != nil {
		return 0, false
	}
	req.Header.Set("Accept", "application/vnd.github+json")
	req.Header.Set("X-GitHub-Api-Version", "2022-11-28")
	req.Header.Set("User-Agent", capability.DefaultAgent())
	req.Header.Set(statsPhaseHeader, "github repo metadata")
	resp, err := sourceConn.HTTP.Do(req)
	if err != nil {
		return 0, false
	}
	defer resp.Body.Close()
	if resp.StatusCode != http.StatusOK {
		return 0, false
	}
	var payload struct {
		Size int64 `json:"size"`
	}
	if err := json.NewDecoder(resp.Body).Decode(&payload); err != nil {
		return 0, false
	}
	if payload.Size <= 0 {
		return 0, false
	}
	return payload.Size, true
}

func githubOwnerRepo(conn *gitproto.Conn) (string, string, bool) {
	if conn == nil || conn.Endpoint == nil {
		return "", "", false
	}
	ep := conn.Endpoint
	if ep.Protocol != "http" && ep.Protocol != "https" {
		return "", "", false
	}
	if !strings.EqualFold(ep.Host, "github.com") {
		return "", "", false
	}
	path := strings.Trim(ep.Path, "/")
	if strings.HasSuffix(path, ".git") {
		path = strings.TrimSuffix(path, ".git")
	}
	parts := strings.Split(path, "/")
	if len(parts) != 2 || parts[0] == "" || parts[1] == "" {
		return "", "", false
	}
	return parts[0], parts[1], true
}

// packpAdvRefsAccessor is a thin wrapper to pass AdvRefs through the interface boundary.
type packpAdvRefsAccessor struct{}

func (a *packpAdvRefsAccessor) advRefs() interface{} { return nil }

package syncer

import (
	"context"
	"errors"
	"fmt"
	"io"
	"strings"

	git "github.com/go-git/go-git/v5"
	"github.com/go-git/go-git/v5/plumbing"
	"github.com/go-git/go-git/v5/plumbing/protocol/packp"
	"github.com/go-git/go-git/v5/storage/memory"

	"github.com/soph/git-sync/internal/gitproto"
	"github.com/soph/git-sync/internal/planner"
)

func bootstrapBatched(
	ctx context.Context,
	cfg Config,
	stats *statsCollector,
	sourceConn, targetConn *gitproto.Conn,
	sourceService *gitproto.RefService,
	targetAdv *packp.AdvRefs,
	plans []BranchPlan,
	desiredRefs map[plumbing.ReferenceName]planner.DesiredRef,
	targetRefs map[plumbing.ReferenceName]plumbing.Hash,
	result Result,
	measurementDone func() Measurement,
) (Result, error) {
	if sourceService.Protocol != protocolModeV2 {
		return result, fmt.Errorf("bootstrap batching currently requires protocol v2")
	}
	if sourceService.V2Caps == nil || !sourceService.V2Caps.FetchSupports("filter") {
		return result, fmt.Errorf("bootstrap batching requires source fetch filter support")
	}

	planRefs := make([]planner.DesiredRef, 0, len(plans))
	tagPlans := make([]BranchPlan, 0, len(plans))
	tagDesired := make(map[plumbing.ReferenceName]gitproto.DesiredRef)
	for _, plan := range plans {
		if plan.Kind == RefKindTag {
			tagPlans = append(tagPlans, plan)
			if d, ok := desiredRefs[plan.TargetRef]; ok {
				tagDesired[plan.TargetRef] = gitproto.DesiredRef{
					SourceRef: d.SourceRef, TargetRef: d.TargetRef,
					SourceHash: d.SourceHash, IsTag: true,
				}
			}
			continue
		}
		if !plan.SourceRef.IsBranch() || !plan.TargetRef.IsBranch() {
			return result, fmt.Errorf("bootstrap batching currently supports branch refs and create-only tags")
		}
		d := desiredRefs[plan.TargetRef]
		planRefs = append(planRefs, d)
	}

	var batches []planner.BootstrapBatch
	if len(planRefs) > 0 {
		progressf(cfg.Verbose, "bootstrap-batch: planning checkpoints for %d branch ref(s)", len(planRefs))
		var err error
		batches, err = planBootstrapBatches(ctx, cfg, sourceConn, sourceService, planRefs, targetRefs)
		if err != nil {
			return result, err
		}
	}

	batchLimit := cfg.BatchMaxPackBytes
	if cfg.MaxPackBytes > 0 && (batchLimit == 0 || cfg.MaxPackBytes < batchLimit) {
		batchLimit = cfg.MaxPackBytes
	}

	for _, batch := range batches {
		result.PlannedBatchCount += len(batch.Checkpoints)
		result.TempRefs = append(result.TempRefs, batch.TempRef.String())
		progressf(cfg.Verbose, "bootstrap-batch: branch=%s temp-ref=%s planned-batches=%d resume=%s",
			batch.Plan.TargetRef, batch.TempRef, len(batch.Checkpoints), planner.ShortHash(batch.ResumeHash))

		current := batch.ResumeHash
		startIdx, err := planner.BootstrapResumeIndex(batch.Checkpoints, batch.ResumeHash)
		if err != nil {
			return result, fmt.Errorf("resume bootstrap batch for %s: %w", batch.Plan.TargetRef, err)
		}

		for idx := startIdx; idx < len(batch.Checkpoints); idx++ {
			checkpoint := batch.Checkpoints[idx]
			progressf(cfg.Verbose, "bootstrap-batch: branch=%s batch=%d/%d from=%s to=%s",
				batch.Plan.TargetRef, idx+1, len(batch.Checkpoints),
				planner.ShortHash(current), planner.ShortHash(checkpoint))

			stagePlans := []BranchPlan{{
				Branch: batch.Plan.Branch, SourceRef: batch.Plan.SourceRef,
				TargetRef: batch.TempRef, SourceHash: checkpoint, TargetHash: current,
				Kind: batch.Plan.Kind, Action: planner.ActionForTargetHash(current),
				Reason: fmt.Sprintf("%s -> %s via %s", planner.ShortHash(current), planner.ShortHash(checkpoint), batch.TempRef),
			}}
			if idx == len(batch.Checkpoints)-1 {
				stagePlans = append(stagePlans, BranchPlan{
					Branch: batch.Plan.Branch, SourceRef: batch.Plan.SourceRef,
					TargetRef: batch.Plan.TargetRef, SourceHash: checkpoint,
					TargetHash: plumbing.ZeroHash, Kind: batch.Plan.Kind,
					Action: ActionCreate,
					Reason: fmt.Sprintf("create %s at %s", batch.Plan.TargetRef, planner.ShortHash(checkpoint)),
				})
			}

			desired := toGitprotoDesiredSingle(batch.Plan.SourceRef, batch.TempRef, checkpoint)
			haves := planner.SingleHaveMap(current)
			packReader, err := sourceService.FetchPack(ctx, sourceConn, desired, haves)
			if err != nil {
				return result, fmt.Errorf("fetch source batch pack for %s: %w", batch.Plan.TargetRef, err)
			}
			packReader = limitPackReadCloser(packReader, batchLimit)
			cmds := plansToPushCommands(stagePlans)
			if err := gitproto.PushPack(ctx, targetConn, targetAdv, cmds, packReader, cfg.Verbose); err != nil {
				return result, fmt.Errorf("push bootstrap batch for %s: %w", batch.Plan.TargetRef, err)
			}
			progressf(cfg.Verbose, "bootstrap-batch: branch=%s batch=%d/%d complete",
				batch.Plan.TargetRef, idx+1, len(batch.Checkpoints))
			current = checkpoint
			result.BatchCount++
		}

		if current.IsZero() {
			return result, fmt.Errorf("bootstrap batching for %s completed with no checkpoint state", batch.Plan.TargetRef)
		}
		if batch.ResumeHash == batch.Plan.SourceHash {
			cmds := []gitproto.PushCommand{{
				Name: batch.Plan.TargetRef, Old: plumbing.ZeroHash, New: batch.Plan.SourceHash,
			}}
			if err := gitproto.PushCommands(ctx, targetConn, targetAdv, cmds, cfg.Verbose); err != nil {
				return result, fmt.Errorf("resume bootstrap cutover for %s: %w", batch.Plan.TargetRef, err)
			}
		}

		// Delete temp ref
		cmds := []gitproto.PushCommand{{Name: batch.TempRef, Old: current, Delete: true}}
		if err := gitproto.PushCommands(ctx, targetConn, targetAdv, cmds, cfg.Verbose); err != nil {
			return result, fmt.Errorf("delete bootstrap temp ref for %s: %w", batch.Plan.TargetRef, err)
		}
		progressf(cfg.Verbose, "bootstrap-batch: branch=%s finalized", batch.Plan.TargetRef)
	}

	// Tag phase (issue #1: tag creation independent of pack necessity)
	if len(tagPlans) > 0 {
		progressf(cfg.Verbose, "bootstrap-batch: pushing %d tag(s) after branch batches", len(tagPlans))
		tagTargetRefs := planner.CopyRefHashMap(targetRefs)
		for _, batch := range batches {
			tagTargetRefs[batch.Plan.TargetRef] = batch.Plan.SourceHash
		}
		packReader, err := sourceService.FetchPack(ctx, sourceConn, tagDesired, tagTargetRefs)
		if err != nil {
			if errors.Is(err, git.NoErrAlreadyUpToDate) {
				// Objects already present — still need to create tag refs (issue #1).
				cmds := plansToPushCommands(tagPlans)
				if err := gitproto.PushCommands(ctx, targetConn, targetAdv, cmds, cfg.Verbose); err != nil {
					return result, fmt.Errorf("create tag refs after bootstrap: %w", err)
				}
			} else {
				return result, fmt.Errorf("fetch bootstrap tag pack: %w", err)
			}
		} else {
			packReader = limitPackReadCloser(packReader, cfg.MaxPackBytes)
			cmds := plansToPushCommands(tagPlans)
			if err := gitproto.PushPack(ctx, targetConn, targetAdv, cmds, packReader, cfg.Verbose); err != nil {
				return result, fmt.Errorf("push bootstrap tags: %w", err)
			}
		}
	}

	result.Pushed = len(plans)
	result.Batching = true
	result.RelayMode = "bootstrap-batch"
	result.Stats = stats.snapshot()
	return result, nil
}

func planBootstrapBatches(
	ctx context.Context,
	cfg Config,
	sourceConn *gitproto.Conn,
	sourceService *gitproto.RefService,
	desired []planner.DesiredRef,
	targetRefs map[plumbing.ReferenceName]plumbing.Hash,
) ([]planner.BootstrapBatch, error) {
	out := make([]planner.BootstrapBatch, 0, len(desired))
	for _, ref := range desired {
		checkpoints, err := planBranchCheckpoints(ctx, cfg, sourceConn, sourceService, ref)
		if err != nil {
			return nil, err
		}
		out = append(out, planner.BootstrapBatch{
			Plan: BranchPlan{
				Branch: ref.Label, SourceRef: ref.SourceRef,
				TargetRef: ref.TargetRef, SourceHash: ref.SourceHash,
				Kind: ref.Kind, Action: ActionCreate,
			},
			TempRef:     planner.BootstrapTempRef(ref.TargetRef),
			ResumeHash:  targetRefs[planner.BootstrapTempRef(ref.TargetRef)],
			Checkpoints: checkpoints,
		})
	}
	return out, nil
}

func planBranchCheckpoints(
	ctx context.Context,
	cfg Config,
	sourceConn *gitproto.Conn,
	sourceService *gitproto.RefService,
	ref planner.DesiredRef,
) ([]plumbing.Hash, error) {
	progressf(cfg.Verbose, "bootstrap-batch: fetching commit graph for %s", ref.TargetRef)
	graphStore := memory.NewStorage()
	gpRef := gitproto.DesiredRef{
		SourceRef: ref.SourceRef, TargetRef: ref.TargetRef, SourceHash: ref.SourceHash,
	}
	if err := sourceService.FetchCommitGraph(ctx, graphStore, sourceConn, gpRef); err != nil {
		return nil, fmt.Errorf("fetch bootstrap planning graph for %s: %w", ref.TargetRef, err)
	}

	chain, err := planner.FirstParentChain(graphStore, ref.SourceHash)
	if err != nil {
		return nil, fmt.Errorf("walk first-parent chain for %s: %w", ref.TargetRef, err)
	}
	if len(chain) == 0 {
		return nil, fmt.Errorf("empty first-parent chain for %s", ref.TargetRef)
	}

	checkpoints := make([]plumbing.Hash, 0, len(chain))
	prevIdx := -1
	prevHash := plumbing.ZeroHash
	prevSpan := 0
	for prevIdx < len(chain)-1 {
		bestIdx, err := planner.SampledCheckpointUnderLimit(chain, prevIdx, prevSpan, func(idx int) (bool, error) {
			tooLarge, err := sourcePackExceedsLimit(ctx, sourceConn, sourceService, ref, chain[idx], prevHash, cfg.BatchMaxPackBytes)
			if err != nil {
				return false, fmt.Errorf("measure bootstrap batch for %s at %s: %w", ref.TargetRef, planner.ShortHash(chain[idx]), err)
			}
			if tooLarge {
				progressf(cfg.Verbose, "bootstrap-batch: sample %s exceeds limit=%d", planner.ShortHash(chain[idx]), cfg.BatchMaxPackBytes)
			} else {
				progressf(cfg.Verbose, "bootstrap-batch: sample %s fits limit=%d", planner.ShortHash(chain[idx]), cfg.BatchMaxPackBytes)
			}
			return tooLarge, nil
		})
		if err != nil {
			return nil, err
		}
		if bestIdx <= prevIdx {
			return nil, fmt.Errorf("could not find bootstrap checkpoint for %s under batch-max-pack-bytes=%d", ref.TargetRef, cfg.BatchMaxPackBytes)
		}
		prevSpan = bestIdx - prevIdx
		prevIdx = bestIdx
		prevHash = chain[bestIdx]
		checkpoints = append(checkpoints, prevHash)
		progressf(cfg.Verbose, "bootstrap-batch: branch=%s planned-checkpoint=%s selected=%d chain-len=%d",
			ref.TargetRef, planner.ShortHash(prevHash), len(checkpoints), len(chain))
	}
	return checkpoints, nil
}

func sourcePackExceedsLimit(
	ctx context.Context,
	sourceConn *gitproto.Conn,
	sourceService *gitproto.RefService,
	ref planner.DesiredRef,
	want, have plumbing.Hash,
	limit int64,
) (bool, error) {
	desired := toGitprotoDesiredSingle(ref.SourceRef, ref.TargetRef, want)
	haves := planner.SingleHaveMap(have)
	packReader, err := sourceService.FetchPack(ctx, sourceConn, desired, haves)
	if err != nil {
		return false, err
	}
	defer packReader.Close()
	_, err = io.Copy(io.Discard, limitPackReadCloser(packReader, limit))
	if err == nil {
		return false, nil
	}
	if strings.Contains(err.Error(), "source pack exceeded max-pack-bytes limit") {
		return true, nil
	}
	return false, err
}

func toGitprotoDesiredSingle(sourceRef, targetRef plumbing.ReferenceName, hash plumbing.Hash) map[plumbing.ReferenceName]gitproto.DesiredRef {
	return map[plumbing.ReferenceName]gitproto.DesiredRef{
		targetRef: {SourceRef: sourceRef, TargetRef: targetRef, SourceHash: hash},
	}
}

