	cmds := make([]gitproto.PushCommand, 0, len(plans))
	for _, p := range plans {
		cmd := gitproto.PushCommand{Name: p.TargetRef, Old: p.TargetHash}
		switch p.Action {
		case planner.ActionCreate, planner.ActionUpdate:
			cmd.New = p.SourceHash
		case planner.ActionDelete:
			cmd.Delete = true
		}
		cmds = append(cmds, cmd)
	}
	return cmds
}

