package syncer

import (
	"context"
	"fmt"
	"net/http"
	"net/http/httptest"
	"testing"

	"github.com/soph/git-sync/internal/gitproto"
	bstrap "github.com/soph/git-sync/internal/strategy/bootstrap"
)

func TestGitHubOwnerRepo(t *testing.T) {
	stats := newStats(false)
	conn, err := newConn(Endpoint{URL: "https://github.com/torvalds/linux.git"}, "source", stats)
	if err != nil {
		t.Fatalf("new conn: %v", err)
	}
	owner, repo, ok := bstrap.GitHubOwnerRepo(conn)
	if !ok {
		t.Fatalf("expected github owner/repo match")
	}
	if owner != "torvalds" || repo != "linux" {
		t.Fatalf("unexpected owner/repo: %s/%s", owner, repo)
	}
}

func TestGitHubOwnerRepoRejectsNonGitHubSource(t *testing.T) {
	stats := newStats(false)
	conn, err := newConn(Endpoint{URL: "https://gitlab.com/group/project.git"}, "source", stats)
	if err != nil {
		t.Fatalf("new conn: %v", err)
	}
	if _, _, ok := bstrap.GitHubOwnerRepo(conn); ok {
		t.Fatalf("expected non-github source to be rejected")
	}
}

func TestGitHubBootstrapBatchMaxPackBytesLargeRepo(t *testing.T) {
	server := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		if r.URL.Path != "/repos/torvalds/linux" {
			t.Fatalf("unexpected path: %s", r.URL.Path)
		}
		w.Header().Set("Content-Type", "application/json")
		_, _ = w.Write([]byte(fmt.Sprintf(`{"size":%d}`, 1536*1024+1)))
	}))
	defer server.Close()

	orig := bstrap.GitHubRepoAPIBaseURL
	bstrap.GitHubRepoAPIBaseURL = server.URL
	t.Cleanup(func() { bstrap.GitHubRepoAPIBaseURL = orig })

	stats := newStats(false)
	conn, err := newConn(Endpoint{URL: "https://github.com/torvalds/linux.git"}, "source", stats)
	if err != nil {
		t.Fatalf("new conn: %v", err)
	}

	svc := &gitproto.RefService{
		Protocol: "v2",
		V2Caps:   &gitproto.V2Capabilities{Caps: map[string]string{"fetch": "thin-pack filter"}},
	}
	bResult, err := bstrap.Execute(context.Background(), bstrap.Params{
		SourceConn:    conn,
		SourceService: svc,
		BatchMaxPack:  0, // trigger GitHub preflight
	}, "test")
	// This will fail because there's no real server, but we're testing the preflight logic.
	// The important thing is it doesn't panic. In a real test we'd mock the target.
	_ = bResult
	_ = err
}

