287	// PlanCheckpoints plans the checkpoint hashes for a single branch during batched bootstrap.
288	func PlanCheckpoints(ctx context.Context, p Params, ref planner.DesiredRef) ([]plumbing.Hash, error) {
289		progressf(p.Verbose, "bootstrap-batch: fetching commit graph for %s", ref.TargetRef)
290		graphStore := memory.NewStorage()
291		gpRef := gitproto.DesiredRef{SourceRef: ref.SourceRef, TargetRef: ref.TargetRef, SourceHash: ref.SourceHash}
292		if err := p.SourceService.FetchCommitGraph(ctx, graphStore, p.SourceConn, gpRef); err != nil {
293			return nil, fmt.Errorf("fetch bootstrap planning graph for %s: %w", ref.TargetRef, err)
294		}
295		chain, err := planner.FirstParentChain(graphStore, ref.SourceHash)
296		if err != nil {
297			return nil, fmt.Errorf("walk first-parent chain for %s: %w", ref.TargetRef, err)
298		}
299		if len(chain) == 0 {
300			return nil, fmt.Errorf("empty first-parent chain for %s", ref.TargetRef)
301		}
302	
303		checkpoints := make([]plumbing.Hash, 0, len(chain))
304		prevIdx := -1
305		prevHash := plumbing.ZeroHash
306		prevSpan := 0
307		for prevIdx < len(chain)-1 {
308			bestIdx, err := planner.SampledCheckpointUnderLimit(chain, prevIdx, prevSpan, func(idx int) (bool, error) {
309				tooLarge, err := packExceedsLimit(ctx, p, ref, chain[idx], prevHash, p.BatchMaxPack)
310				if err != nil {
311					return false, fmt.Errorf("measure bootstrap batch for %s at %s: %w", ref.TargetRef, planner.ShortHash(chain[idx]), err)
312				}
313				return tooLarge, nil
314			})
315			if err != nil {
316				return nil, err
317			}
318			if bestIdx <= prevIdx {
319				return nil, fmt.Errorf("could not find bootstrap checkpoint for %s under batch-max-pack-bytes=%d", ref.TargetRef, p.BatchMaxPack)
320			}
321			prevSpan = bestIdx - prevIdx
322			prevIdx = bestIdx
323			prevHash = chain[bestIdx]
324			checkpoints = append(checkpoints, prevHash)
325			progressf(p.Verbose, "bootstrap-batch: branch=%s planned-checkpoint=%s selected=%d chain-len=%d",
326				ref.TargetRef, planner.ShortHash(prevHash), len(checkpoints), len(chain))
327		}
328		return checkpoints, nil
329	}
